{
  "name": "LinguaWordle",
  "description": "A Wordle-like language learning game supporting English and Russian, custom dictionaries, and AI-powered context hints."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Language = 'EN' | 'RU';
export type WordLength = 4 | 5 | 6;

export type CharStatus = 'correct' | 'present' | 'absent' | 'initial';

export interface CellData {
  letter: string;
  status: CharStatus;
}

export interface GameSettings {
  language: Language;
  wordLength: WordLength;
  customDictionary: string[]; // Array of words loaded from file
  useCustomDictionary: boolean;
}

export interface GameState {
  secretWord: string;
  guesses: string[]; // List of words guessed so far
  currentGuess: string; // Current input being typed
  gameStatus: 'playing' | 'won' | 'lost';
  rowIndex: number;
  hint: string | null;
  loadingHint: boolean;
  error: string | null;
}

export interface KeyboardKey {
  key: string;
  status?: CharStatus;
}

import { Language } from './types';

export const ALPHABET_EN = [
  'Q', 'W', 'E', 'R', 'T', 'Y', 'U', 'I', 'O', 'P',
  'A', 'S', 'D', 'F', 'G', 'H', 'J', 'K', 'L',
  'Z', 'X', 'C', 'V', 'B', 'N', 'M'
];

export const ALPHABET_RU = [
  'Й', 'Ц', 'У', 'К', 'Е', 'Н', 'Г', 'Ш', 'Щ', 'З', 'Х', 'Ъ',
  'Ф', 'Ы', 'В', 'А', 'П', 'Р', 'О', 'Л', 'Д', 'Ж', 'Э',
  'Я', 'Ч', 'С', 'М', 'И', 'Т', 'Ь', 'Б', 'Ю'
];

// Small fallback dictionaries to ensure the app works without upload
export const DEFAULT_WORDS_EN = [
  "READ", "BOOK", "GAME", "PLAY", // 4
  "APPLE", "TABLE", "HOUSE", "WORLD", // 5
  "SCHOOL", "FAMILY", "FRIEND", "ORANGE" // 6
];

export const DEFAULT_WORDS_RU = [
  "ИГРА", "СТОЛ", "ДОМ", "СНЕГ", // 4
  "КНИГА", "ШКОЛА", "УЛИЦА", "ПОЕЗД", // 5
  "СОЛНЦЕ", "ДРУЗЬЯ", "РАБОТА", "МОСКВА" // 6
];

export const KEYBOARD_LAYOUT_EN = [
  ['Q', 'W', 'E', 'R', 'T', 'Y', 'U', 'I', 'O', 'P'],
  ['A', 'S', 'D', 'F', 'G', 'H', 'J', 'K', 'L'],
  ['ENTER', 'Z', 'X', 'C', 'V', 'B', 'N', 'M', 'BACKSPACE']
];

export const KEYBOARD_LAYOUT_RU = [
  ['Й', 'Ц', 'У', 'К', 'Е', 'Н', 'Г', 'Ш', 'Щ', 'З', 'Х', 'Ъ'],
  ['Ф', 'Ы', 'В', 'А', 'П', 'Р', 'О', 'Л', 'Д', 'Ж', 'Э'],
  ['ENTER', 'Я', 'Ч', 'С', 'М', 'И', 'Т', 'Ь', 'Б', 'Ю', 'BACKSPACE']
];

export const MAX_GUESSES = 6;

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
// Note: In a real production app, ensure API_KEY is set. 
// If not set, we'll handle the error gracefully in the UI.

const ai = new GoogleGenAI({ apiKey });

export const generateHint = async (secretWord: string): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Cannot generate hint.");
  }

  const prompt = `
    Context: The secret word for a word-guessing game is "${secretWord}".
    Audience: School students learning English.
    Task: Create a simple, easy-to-understand sentence where this word fits perfectly, but replace the word (and only the word) with "_______" (underscores).
    Constraint: Do not mention the secret word itself anywhere in the output. Just the sentence.
    Example if word is "APPLE": "I ate a red _______ for lunch."
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    const text = response.text;
    if (!text) return "Could not generate a hint.";
    return text.trim();
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to contact AI service.");
  }
};

import React from 'react';
import { WordLength, CharStatus } from '../types';

interface GridProps {
  guesses: string[];
  currentGuess: string;
  secretWord: string;
  wordLength: WordLength;
  maxGuesses: number;
}

const Cell: React.FC<{ letter: string; status: CharStatus }> = ({ letter, status }) => {
  let baseClasses = "w-12 h-12 sm:w-14 sm:h-14 border-2 flex items-center justify-center text-2xl font-bold uppercase select-none transition-all duration-300";
  let statusClasses = "";

  switch (status) {
    case 'correct':
      statusClasses = "bg-green-500 border-green-500 text-white";
      break;
    case 'present':
      statusClasses = "bg-yellow-500 border-yellow-500 text-white";
      break;
    case 'absent':
      statusClasses = "bg-gray-500 border-gray-500 text-white";
      break;
    default:
      statusClasses = letter ? "border-gray-400 text-black scale-105" : "border-gray-200";
      break;
  }

  return (
    <div className={`${baseClasses} ${statusClasses}`}>
      {letter}
    </div>
  );
};

export const Grid: React.FC<GridProps> = ({ guesses, currentGuess, secretWord, wordLength, maxGuesses }) => {
  // Helper to determine status of a letter in a submitted guess
  const getLetterStatus = (word: string, index: number, letter: string): CharStatus => {
    if (!word) return 'initial';
    if (secretWord[index] === letter) return 'correct';
    if (secretWord.includes(letter)) return 'present'; // Simplified Wordle logic for display purposes here
    return 'absent';
  };

  // Refined Wordle Logic for coloring a full row correctly (handling duplicates)
  const getRowStatuses = (guess: string): CharStatus[] => {
    const statuses: CharStatus[] = Array(wordLength).fill('absent');
    const secretArr = secretWord.split('');
    const guessArr = guess.split('');

    // First pass: Correct
    guessArr.forEach((char, i) => {
      if (char === secretArr[i]) {
        statuses[i] = 'correct';
        secretArr[i] = '#'; // Mark as handled
      }
    });

    // Second pass: Present
    guessArr.forEach((char, i) => {
      if (statuses[i] !== 'correct') {
        const indexInSecret = secretArr.indexOf(char);
        if (indexInSecret !== -1) {
          statuses[i] = 'present';
          secretArr[indexInSecret] = '#'; // Mark as handled
        }
      }
    });

    return statuses;
  };

  const rows = [];

  // Render past guesses
  for (let i = 0; i < maxGuesses; i++) {
    if (i < guesses.length) {
      const guess = guesses[i];
      const statuses = getRowStatuses(guess);
      rows.push(
        <div key={i} className="flex gap-1 mb-1 justify-center">
          {guess.split('').map((letter, idx) => (
            <Cell key={idx} letter={letter} status={statuses[idx]} />
          ))}
        </div>
      );
    } else if (i === guesses.length) {
      // Current row being typed
      const chars = currentGuess.split('');
      rows.push(
        <div key={i} className="flex gap-1 mb-1 justify-center">
          {Array.from({ length: wordLength }).map((_, idx) => (
            <Cell key={idx} letter={chars[idx] || ''} status="initial" />
          ))}
        </div>
      );
    } else {
      // Empty rows
      rows.push(
        <div key={i} className="flex gap-1 mb-1 justify-center">
          {Array.from({ length: wordLength }).map((_, idx) => (
            <Cell key={idx} letter="" status="initial" />
          ))}
        </div>
      );
    }
  }

  return <div className="grid grid-rows-6 gap-1 p-2">{rows}</div>;
};

import React, { useMemo } from 'react';
import { KEYBOARD_LAYOUT_EN, KEYBOARD_LAYOUT_RU } from '../constants';
import { CharStatus, Language } from '../types';

interface KeyboardProps {
  onChar: (char: string) => void;
  onDelete: () => void;
  onEnter: () => void;
  language: Language;
  letterStatuses: Record<string, CharStatus>;
}

export const Keyboard: React.FC<KeyboardProps> = ({ onChar, onDelete, onEnter, language, letterStatuses }) => {
  const layout = language === 'EN' ? KEYBOARD_LAYOUT_EN : KEYBOARD_LAYOUT_RU;

  const getKeyClass = (key: string) => {
    const status = letterStatuses[key];
    let base = "h-14 flex items-center justify-center rounded font-bold text-sm cursor-pointer select-none transition-colors active:scale-95 ";

    // Width adjustments
    if (key === 'ENTER' || key === 'BACKSPACE') {
      base += "px-3 sm:px-4 text-xs sm:text-sm flex-grow-[1.5] ";
    } else {
      base += "flex-1 w-8 sm:w-10 ";
    }

    // Color based on status
    if (status === 'correct') return base + "bg-green-500 text-white";
    if (status === 'present') return base + "bg-yellow-500 text-white";
    if (status === 'absent') return base + "bg-gray-500 text-white";

    return base + "bg-gray-200 hover:bg-gray-300 text-black";
  };

  const renderKey = (key: string) => {
    const label = key === 'BACKSPACE' ? (
       <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
        <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12l-2.25 2.25m-2.25-2.25l-2.25 2.25m0 0l-2.25-2.25m2.25 2.25L9.75 9.75M9.75 12l-2.25 2.25m2.25-2.25l-2.25-2.25m6 3V12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12l-2.25 2.25m-2.25-2.25l-2.25 2.25m0 0l-2.25-2.25m2.25 2.25L9.75 9.75M9.75 12l-2.25 2.25m2.25-2.25l-2.25-2.25" />
        <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5h-6a2.25 2.25 0 01-2.25-2.25v-10.5A2.25 2.25 0 014.5 4.5h6l5.25 5.25 5.25 5.25-10.5 4.5z" /> 
        {/* Simplified Backspace Icon */}
        <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12l-2.25 2.25m-2.25-2.25l-2.25 2.25m0 0l-2.25-2.25m2.25 2.25L9.75 9.75M9.75 12l-2.25 2.25m2.25-2.25l-2.25-2.25" />
      </svg>
    ) : key;

    const actualLabel = key === 'BACKSPACE' ? '⌫' : key;

    return (
      <button
        key={key}
        className={getKeyClass(key)}
        onClick={() => {
          if (key === 'ENTER') onEnter();
          else if (key === 'BACKSPACE') onDelete();
          else onChar(key);
        }}
      >
        {actualLabel}
      </button>
    );
  };

  return (
    <div className="w-full max-w-2xl px-2 pb-4">
      {layout.map((row, i) => (
        <div key={i} className="flex gap-1.5 mb-1.5 justify-center">
          {row.map(renderKey)}
        </div>
      ))}
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameSettings, GameState, Language, WordLength, CharStatus } from './types';
import { DEFAULT_WORDS_EN, DEFAULT_WORDS_RU, MAX_GUESSES } from './constants';
import { Grid } from './components/Grid';
import { Keyboard } from './components/Keyboard';
import { generateHint } from './services/geminiService';

// --- Icons ---
const SettingsIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.09a2 2 0 0 1-1-1.74v-.51a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.38a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z"></path><circle cx="12" cy="12" r="3"></circle></svg>
);
const RefreshIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"></path><path d="M16 21h5v-5"></path></svg>
);

const App: React.FC = () => {
  // --- State ---
  const [settings, setSettings] = useState<GameSettings>({
    language: 'EN',
    wordLength: 5,
    customDictionary: [],
    useCustomDictionary: false,
  });

  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    guesses: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(true); // Open settings initially to let user choose
  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  // --- Helpers ---
  const getDictionary = useCallback(() => {
    let pool: string[] = [];

    // 1. Choose Source
    if (settings.language === 'EN' && settings.useCustomDictionary && settings.customDictionary.length > 0) {
      pool = settings.customDictionary;
    } else {
      pool = settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU;
    }

    // 2. Filter by Length
    const filtered = pool.filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());

    // Fallback if no words of that length exist in current pool
    if (filtered.length === 0) {
      // If custom dict fails, try default
      if (settings.useCustomDictionary) {
         const fallback = (settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU)
          .filter(w => w.length === settings.wordLength)
          .map(w => w.toUpperCase());
         return fallback;
      }
      return [];
    }
    return filtered;
  }, [settings]);

  const startNewGame = useCallback(() => {
    const words = getDictionary();
    if (words.length === 0) {
      setGameState(prev => ({ ...prev, error: "No words found for this configuration.", gameStatus: 'lost' }));
      return;
    }

    const randomWord = words[Math.floor(Math.random() * words.length)];

    setGameState({
      secretWord: randomWord,
      guesses: [],
      currentGuess: '',
      gameStatus: 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: null,
    });
    setKeyStatuses({});
    setIsSettingsOpen(false); // Close modal on start
  }, [getDictionary]);

  // Initial Game Start
  useEffect(() => {
    // Only auto-start if we aren't waiting for user config in initial load
    // But since we want user to configure, we leave modal open.
    // Logic: if secret word is empty, we haven't started.
    if (!gameState.secretWord && !isSettingsOpen) {
      startNewGame();
    }
  }, [gameState.secretWord, isSettingsOpen, startNewGame]);


  // --- Logic ---

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1) }));
  };

  const handleEnter = () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) {
      // Shake animation trigger could go here
      return;
    }

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    // Update Key Statuses
    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      // If currently correct, stay correct.
      // If currently present, become correct if matches, else stay present.
      // If absent, stay absent.
      const currentStatus = newKeyStatuses[char];

      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    // Check Win/Loss
    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1
    }));
  };

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (isSettingsOpen) return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;

    if (e.key === 'Enter') {
      handleEnter();
    } else if (e.key === 'Backspace') {
      handleDelete();
    } else {
      const char = e.key.toUpperCase();
      // Basic validation for EN/RU input
      const isEnChar = /^[A-Z]$/.test(char);
      const isRuChar = /^[А-ЯЁ]$/.test(char); // Basic cyrillic range check

      if (settings.language === 'EN' && isEnChar) handleChar(char);
      else if (settings.language === 'RU' && isRuChar) handleChar(char);
    }
  }, [gameState, settings, isSettingsOpen, keyStatuses]); // Deps simplified for example

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);


  // --- Feature Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      // Split by newline, spaces, commas
      const rawWords = text.split(/[\n\s,]+/);
      // Clean words: trim, uppercase, remove non-alpha
      const cleanedWords = rawWords
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
        .filter(w => w.length > 0);

      setSettings(prev => ({
        ...prev,
        customDictionary: cleanedWords,
        useCustomDictionary: true
      }));
    };
    reader.readAsText(file);
  };

  const fetchHint = async () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, loadingHint: true }));
    try {
      const hintText = await generateHint(gameState.secretWord);
      setGameState(prev => ({ ...prev, hint: hintText, loadingHint: false }));
    } catch (e) {
      setGameState(prev => ({ ...prev, hint: "Failed to load hint.", loadingHint: false }));
    }
  };

  // --- Render ---

  return (
    <div className="flex flex-col h-screen items-center bg-gray-50 overflow-hidden relative">
      {/* Header */}
      <header className="w-full border-b bg-white p-4 flex justify-between items-center shadow-sm z-10">
        <div className="w-8"></div>
        <h1 className="text-2xl font-bold tracking-wider">
          LINGUA<span className="text-green-600">WORDLE</span>
        </h1>
        <button onClick={() => setIsSettingsOpen(true)} className="p-2 hover:bg-gray-100 rounded-full">
          <SettingsIcon />
        </button>
      </header>

      {/* Main Game Area */}
      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-lg p-4 overflow-y-auto">

        {/* Hint Section */}
        {settings.language === 'EN' && gameState.gameStatus === 'playing' && (
           <div className="w-full mb-4 flex flex-col items-center min-h-[3rem]">
             {!gameState.hint ? (
               <button 
                onClick={fetchHint}
                disabled={gameState.loadingHint}
                className="text-xs sm:text-sm bg-indigo-100 text-indigo-700 px-4 py-2 rounded-full font-semibold hover:bg-indigo-200 transition disabled:opacity-50"
               >
                 {gameState.loadingHint ? 'Thinking...' : '💡 Get AI Hint'}
               </button>
             ) : (
               <div className="bg-indigo-50 border border-indigo-200 text-indigo-800 p-3 rounded-lg text-sm text-center shadow-sm animate-fade-in w-full">
                 <span className="font-bold">Hint:</span> {gameState.hint}
               </div>
             )}
           </div>
        )}

        <Grid 
          guesses={gameState.guesses}
          currentGuess={gameState.currentGuess}
          secretWord={gameState.secretWord}
          wordLength={settings.wordLength}
          maxGuesses={MAX_GUESSES}
        />

        {/* Game Over Message */}
        {gameState.gameStatus !== 'playing' && (
          <div className="mt-4 p-4 bg-white rounded-lg shadow-md border text-center animate-bounce-in">
             <h2 className="text-xl font-bold mb-2">
               {gameState.gameStatus === 'won' ? '🎉 You Won!' : '😔 Game Over'}
             </h2>
             <p className="mb-4 text-gray-700">
               The word was: <span className="font-bold text-black">{gameState.secretWord}</span>
             </p>
             <button 
               onClick={startNewGame}
               className="bg-green-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-green-700 flex items-center gap-2 mx-auto"
             >
               <RefreshIcon /> Play Again
             </button>
          </div>
        )}
      </main>

      {/* Keyboard Area */}
      <footer className="w-full bg-gray-100 pb-2 pt-2 border-t flex justify-center">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="absolute inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-md">
            <h2 className="text-2xl font-bold mb-6 text-center">Settings</h2>

            {/* Language Selection */}
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">Language</label>
              <div className="flex bg-gray-100 rounded-lg p-1">
                <button 
                  onClick={() => setSettings(s => ({...s, language: 'EN'}))}
                  className={`flex-1 py-2 rounded-md font-medium transition ${settings.language === 'EN' ? 'bg-white shadow text-green-600' : 'text-gray-500'}`}
                >
                  English
                </button>
                <button 
                   onClick={() => setSettings(s => ({...s, language: 'RU'}))}
