            {/* Custom Dictionary (EN Only) */}
            {settings.language === 'EN' && (
              <div className="mb-6 p-4 bg-yellow-50 rounded-lg border border-yellow-100">
                <label className="block text-sm font-semibold text-yellow-800 mb-2">
                  Custom Dictionary (Student Mode)
                </label>
                <input 
                  type="file" 
                  accept=".txt" 
                  onChange={handleFileUpload}
                  className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-yellow-100 file:text-yellow-700 hover:file:bg-yellow-200"
                />
                {settings.useCustomDictionary && (
                  <p className="text-xs text-green-600 mt-2">
                    ✓ Loaded {settings.customDictionary.length} words.
                  </p>
                )}
                <p className="text-xs text-gray-500 mt-2">
                  Upload a .txt file with words separated by spaces or newlines.
                </p>
              </div>
            )}

            <button 
              onClick={startNewGame}
              className="w-full bg-green-600 text-white py-3 rounded-lg font-bold text-lg hover:bg-green-700 transition shadow-lg transform active:scale-95"
            >
              Start Game
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

