import React, { useState, useEffect, useCallback } from 'react';
import { GameSettings, GameState, CharStatus, UserProfile, WordLength } from './types';
import { DEFAULT_WORDS_EN, DEFAULT_WORDS_RU, MAX_GUESSES } from './constants';
import { Grid } from './components/Grid';
import { Keyboard } from './components/Keyboard';
import { getAlgorithmicHint } from './services/hintService';

// --- Icons ---
const SettingsIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.09a2 2 0 0 1-1-1.74v-.51a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.38a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z"></path><circle cx="12" cy="12" r="3"></circle></svg>
);
const RefreshIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"></path><path d="M16 21h5v-5"></path></svg>
);

const App: React.FC = () => {
  // --- State ---
  const [settings, setSettings] = useState<GameSettings>({
    language: 'EN',
    wordLength: 5,
    useCustomDictionary: false,
    username: 'Guest',
  });

  // Current active profile data
  const [userProfile, setUserProfile] = useState<UserProfile>({
    username: 'Guest',
    customDictionaryEn: [],
    stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
  });

  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    guesses: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(true);
  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  // --- Profile Management ---

  // Load profile when username changes
  useEffect(() => {
    const saved = localStorage.getItem(`annword_user_${settings.username}`);
    if (saved) {
      setUserProfile(JSON.parse(saved));
    } else {
      // Create new profile default
      setUserProfile({
        username: settings.username,
        customDictionaryEn: [],
        stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
      });
    }
  }, [settings.username]);

  // Save profile whenever it changes
  useEffect(() => {
    if (userProfile.username) {
      localStorage.setItem(`annword_user_${userProfile.username}`, JSON.stringify(userProfile));
    }
  }, [userProfile]);


  // --- Game Helpers ---

  const getDictionary = useCallback(() => {
    let pool: string[] = [];

    // 1. Choose Source
    if (settings.language === 'EN' && settings.useCustomDictionary && userProfile.customDictionaryEn.length > 0) {
      pool = userProfile.customDictionaryEn;
    } else {
      pool = settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU;
    }

    // 2. Filter by Length
    const filtered = pool.filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());

    // Fallback if no words of that length exist in current pool
    if (filtered.length === 0) {
      if (settings.useCustomDictionary) {
         // Fallback to default if custom has no words of this length
         const fallback = (settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU)
          .filter(w => w.length === settings.wordLength)
          .map(w => w.toUpperCase());
         return fallback;
      }
      return [];
    }
    return filtered;
  }, [settings, userProfile.customDictionaryEn]);

  const startNewGame = useCallback(() => {
    const words = getDictionary();
    if (words.length === 0) {
      setGameState(prev => ({ ...prev, error: "Слов с такими настройками не найдено.", gameStatus: 'lost' }));
      return;
    }

    const randomWord = words[Math.floor(Math.random() * words.length)];

    setGameState({
      secretWord: randomWord,
      guesses: [],
      currentGuess: '',
      gameStatus: 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: null,
    });
    setKeyStatuses({});
    setIsSettingsOpen(false);
  }, [getDictionary]);

  // Initial Auto Start Logic
  useEffect(() => {
    if (!gameState.secretWord && !isSettingsOpen) {
      startNewGame();
    }
  }, [gameState.secretWord, isSettingsOpen, startNewGame]);


  // --- Logic ---

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1) }));
  };

  const updateStats = (won: boolean, word: string) => {
    setUserProfile(prev => {
      const newStats = { ...prev.stats };
      newStats.gamesPlayed += 1;
      if (won) {
        newStats.gamesWon += 1;
        newStats.wordsGuessed[word] = (newStats.wordsGuessed[word] || 0) + 1;
      }
      return { ...prev, stats: newStats };
    });
  };

  const handleEnter = () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) return;

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    // Update Key Statuses
    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      const currentStatus = newKeyStatuses[char];
      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    // Check Win/Loss
    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      updateStats(true, gameState.secretWord);
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      updateStats(false, gameState.secretWord);
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null // Reset hint on new turn
    }));
  };

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (isSettingsOpen) return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;

    if (e.key === 'Enter') {
      handleEnter();
    } else if (e.key === 'Backspace') {
      handleDelete();
    } else {
      const char = e.key.toUpperCase();
      const isEnChar = /^[A-Z]$/.test(char);
      const isRuChar = /^[А-ЯЁ]$/.test(char);

      if (settings.language === 'EN' && isEnChar) handleChar(char);
      else if (settings.language === 'RU' && isRuChar) handleChar(char);
    }
  }, [gameState, settings, isSettingsOpen, keyStatuses]); 

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);


  // --- Feature Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const rawWords = text.split(/[\n\s,]+/);
      const cleanedWords = rawWords
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
        .filter(w => w.length > 0);

      // Save dictionary to current profile
      setUserProfile(prev => ({
        ...prev,
        customDictionaryEn: cleanedWords
      }));

      setSettings(prev => ({
        ...prev,
        useCustomDictionary: true
      }));
    };
    reader.readAsText(file);
  };

  const fetchHint = () => {
    if (gameState.gameStatus !== 'playing') return;

    // Algorithmic Hint
    const currentDict = getDictionary();
    const hintWord = getAlgorithmicHint(gameState.secretWord, gameState.guesses, currentDict);
    setGameState(prev => ({ ...prev, hint: hintWord }));
  };

  // --- Render ---

  return (
    <div className="flex flex-col h-screen items-center bg-gray-50 overflow-hidden relative">
      {/* Header */}
      <header className="w-full border-b bg-white p-4 flex justify-between items-center shadow-sm z-10">
        <div className="w-8"></div>
        <h1 className="text-2xl font-bold tracking-wider">
          ANN<span className="text-green-600">WORD</span>
        </h1>
        <button onClick={() => setIsSettingsOpen(true)} className="p-2 hover:bg-gray-100 rounded-full">
          <SettingsIcon />
        </button>
      </header>

      {/* Main Game Area */}
      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-lg p-4 overflow-y-auto">

        {/* Hint Section (Available for both langs now as it's algorithmic) */}
        {settings.language === 'EN' && gameState.gameStatus === 'playing' && (
           <div className="w-full mb-4 flex flex-col items-center min-h-[3rem]">
             {!gameState.hint ? (
               <button 
                onClick={fetchHint}
                className="text-xs sm:text-sm bg-indigo-100 text-indigo-700 px-4 py-2 rounded-full font-semibold hover:bg-indigo-200 transition"
               >
                 💡 Подсказка (Слово)
               </button>
             ) : (
               <div className="bg-indigo-50 border border-indigo-200 text-indigo-800 p-3 rounded-lg text-sm text-center shadow-sm animate-fade-in w-full">
                 <span className="font-bold">Попробуйте ввести:</span> {gameState.hint}
               </div>
             )}
           </div>
        )}

        <Grid 
          guesses={gameState.guesses}
          currentGuess={gameState.currentGuess}
          secretWord={gameState.secretWord}
          wordLength={settings.wordLength}
          maxGuesses={MAX_GUESSES}
        />

        {/* Game Over Message */}
        {gameState.gameStatus !== 'playing' && (
          <div className="mt-4 p-4 bg-white rounded-lg shadow-md border text-center animate-bounce-in">
             <h2 className="text-xl font-bold mb-2">
               {gameState.gameStatus === 'won' ? '🎉 Победа!' : '😔 Вы проиграли'}
             </h2>
             <p className="mb-4 text-gray-700">
               Загаданное слово: <span className="font-bold text-black">{gameState.secretWord}</span>
             </p>
             <button 
               onClick={startNewGame}
               className="bg-green-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-green-700 flex items-center gap-2 mx-auto"
             >
               <RefreshIcon /> Играть снова
             </button>
          </div>
        )}
      </main>

      {/* Keyboard Area */}
      <footer className="w-full bg-gray-100 pb-2 pt-2 border-t flex justify-center">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="absolute inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-md max-h-[90vh] overflow-y-auto">
            <h2 className="text-2xl font-bold mb-4 text-center">Настройки AnnWord</h2>

            {/* Profile Section */}
            <div className="mb-6 p-4 bg-blue-50 rounded-lg border border-blue-100">
               <label className="block text-sm font-semibold text-blue-900 mb-2">Имя пользователя</label>
               <input 
                 type="text" 
                 value={settings.username}
                 onChange={(e) => setSettings(s => ({...s, username: e.target.value}))}
                 className="w-full p-2 border rounded shadow-sm focus:ring-2 focus:ring-blue-400 outline-none"
                 placeholder="Введите имя..."
               />

               {/* Stats */}
               <div className="mt-4 grid grid-cols-2 gap-2 text-center">
                  <div className="bg-white p-2 rounded shadow-sm">
                     <div className="text-xl font-bold text-gray-800">{userProfile.stats.gamesPlayed}</div>
                     <div className="text-xs text-gray-500 uppercase">Игр</div>
                  </div>
                  <div className="bg-white p-2 rounded shadow-sm">
                     <div className="text-xl font-bold text-green-600">{userProfile.stats.gamesWon}</div>
                     <div className="text-xs text-gray-500 uppercase">Побед</div>
                  </div>
               </div>

               <div className="mt-3 text-xs text-gray-600">
                 <p className="font-bold mb-1">Топ выученных слов:</p>
                 <div className="flex flex-wrap gap-1">
                   {Object.entries(userProfile.stats.wordsGuessed)
                     .sort(([, countA], [, countB]) => (countB as number) - (countA as number))
                     .slice(0, 5)
                     .map(([word, count]) => (
                       <span key={word} className="bg-white px-2 py-0.5 rounded border text-gray-700">{word} ({count})</span>
                   ))}
                   {Object.keys(userProfile.stats.wordsGuessed).length === 0 && <span>Нет данных</span>}
                 </div>
               </div>
            </div>

            {/* Language Selection */}
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">Язык</label>
              <div className="flex bg-gray-100 rounded-lg p-1">
                <button 
                  onClick={() => setSettings(s => ({...s, language: 'EN'}))}
                  className={`flex-1 py-2 rounded-md font-medium transition ${settings.language === 'EN' ? 'bg-white shadow text-green-600' : 'text-gray-500'}`}
                >
                  English
                </button>
                <button 
                   onClick={() => setSettings(s => ({...s, language: 'RU'}))}
                   className={`flex-1 py-2 rounded-md font-medium transition ${settings.language === 'RU' ? 'bg-white shadow text-green-600' : 'text-gray-500'}`}
                >
                  Русский
                </button>
              </div>
            </div>

            {/* Word Length */}
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">Длина слова</label>
              <div className="flex justify-between gap-2">
                {[4, 5, 6].map(len => (
                  <button
                    key={len}
                    onClick={() => setSettings(s => ({...s, wordLength: len as WordLength}))}
                    className={`flex-1 py-3 rounded-lg border-2 font-bold transition ${settings.wordLength === len ? 'border-green-500 bg-green-50 text-green-700' : 'border-gray-200 text-gray-600 hover:border-gray-300'}`}
                  >
                    {len} Букв
                  </button>
                ))}
              </div>
            </div>

            {/* Custom Dictionary (EN Only) */}
            {settings.language === 'EN' && (
              <div className="mb-6 p-4 bg-yellow-50 rounded-lg border border-yellow-100">
                <label className="block text-sm font-semibold text-yellow-800 mb-2">
                  Словарь пользователя {settings.username}
                </label>
                <input 
                  type="file" 
                  accept=".txt" 
                  onChange={handleFileUpload}
                  className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-yellow-100 file:text-yellow-700 hover:file:bg-yellow-200"
                />
                <div className="mt-2 flex items-center gap-2">
                    <input 
                      type="checkbox" 
                      id="useCustom"
                      checked={settings.useCustomDictionary}
                      onChange={(e) => setSettings(s => ({...s, useCustomDictionary: e.target.checked}))}
                      disabled={userProfile.customDictionaryEn.length === 0}
                    />
                    <label htmlFor="useCustom" className={`text-sm ${userProfile.customDictionaryEn.length === 0 ? 'text-gray-400' : 'text-gray-700'}`}>
                        Использовать мой словарь ({userProfile.customDictionaryEn.length} слов)
                    </label>
                </div>
                <p className="text-xs text-gray-500 mt-2">
                  Загрузите .txt файл для текущего пользователя.
                </p>
              </div>
            )}

            <button 
              onClick={startNewGame}
              className="w-full bg-green-600 text-white py-3 rounded-lg font-bold text-lg hover:bg-green-700 transition shadow-lg transform active:scale-95"
            >
              Начать игру
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { GameSettings, GameState, CharStatus, UserProfile, WordLength } from './types';
import { DEFAULT_WORDS_EN, DEFAULT_WORDS_RU, MAX_GUESSES } from './constants';
import { Grid } from './components/Grid';
import { Keyboard } from './components/Keyboard';
import { getAlgorithmicHint } from './services/hintService';

// --- Icons ---
const HomeIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
);
const RefreshIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"></path><path d="M16 21h5v-5"></path></svg>
);
const UserIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg>
);

const App: React.FC = () => {
  // --- State ---
  const [view, setView] = useState<'landing' | 'game'>('landing');

  const [settings, setSettings] = useState<GameSettings>({
    language: 'EN',
    wordLength: 5,
    useCustomDictionary: false,
    username: 'Guest',
  });

  // Current active profile data
  const [userProfile, setUserProfile] = useState<UserProfile>({
    username: 'Guest',
    customDictionaryEn: [],
    stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
  });

  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    guesses: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });

  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  // --- Profile Management ---

  // Load profile when username changes
  useEffect(() => {
    // Only load if we are on landing page or specifically changing user
    const saved = localStorage.getItem(`annword_user_${settings.username}`);
    let loadedProfile: UserProfile;

    if (saved) {
      loadedProfile = JSON.parse(saved);
    } else {
      loadedProfile = {
        username: settings.username,
        customDictionaryEn: [],
        stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
      };
    }
    setUserProfile(loadedProfile);

    // FIX: Auto-enable custom dictionary if user has one loaded
    // This ensures that when returning to a user, their dictionary preference is respected/available
    if (loadedProfile.customDictionaryEn.length > 0) {
      setSettings(prev => ({ ...prev, useCustomDictionary: true }));
    } else {
      setSettings(prev => ({ ...prev, useCustomDictionary: false }));
    }
  }, [settings.username]);

  // Save profile whenever it changes
  useEffect(() => {
    if (userProfile.username) {
      localStorage.setItem(`annword_user_${userProfile.username}`, JSON.stringify(userProfile));
    }
  }, [userProfile]);


  // --- Game Helpers ---

  const getDictionary = useCallback(() => {
    let pool: string[] = [];

    // 1. Choose Source
    // Explicitly check current settings state
    if (settings.language === 'EN' && settings.useCustomDictionary && userProfile.customDictionaryEn.length > 0) {
      pool = userProfile.customDictionaryEn;
    } else {
      pool = settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU;
    }

    // 2. Filter by Length
    const filtered = pool.filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());

    // Fallback if no words of that length exist in current pool
    if (filtered.length === 0) {
      // If custom dict fails (empty for this length), try default as fallback
      if (settings.useCustomDictionary) {
         const fallback = (settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU)
          .filter(w => w.length === settings.wordLength)
          .map(w => w.toUpperCase());
         return fallback;
      }
      return [];
    }
    return filtered;
  }, [settings.language, settings.useCustomDictionary, settings.wordLength, userProfile.customDictionaryEn]);

  const startNewGame = useCallback(() => {
    const words = getDictionary();
    if (words.length === 0) {
      setGameState(prev => ({ ...prev, error: "Слов с такими настройками не найдено.", gameStatus: 'lost' }));
      return;
    }

    const randomWord = words[Math.floor(Math.random() * words.length)];

    setGameState({
      secretWord: randomWord,
      guesses: [],
      currentGuess: '',
      gameStatus: 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: null,
    });
    setKeyStatuses({});
    setView('game'); // Ensure we are in game view
  }, [getDictionary]);


  // --- Logic ---

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1) }));
  };

  const updateStats = (won: boolean, word: string) => {
    setUserProfile(prev => {
      const newStats = { ...prev.stats };
      newStats.gamesPlayed += 1;
      if (won) {
        newStats.gamesWon += 1;
        newStats.wordsGuessed[word] = (newStats.wordsGuessed[word] || 0) + 1;
      }
      return { ...prev, stats: newStats };
    });
  };

  const handleEnter = () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) return;

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    // Update Key Statuses
    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      const currentStatus = newKeyStatuses[char];
      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    // Check Win/Loss
    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      updateStats(true, gameState.secretWord);
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      updateStats(false, gameState.secretWord);
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null // Reset hint on new turn
    }));
  };

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (view !== 'game') return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;

    if (e.key === 'Enter') {
      handleEnter();
    } else if (e.key === 'Backspace') {
      handleDelete();
    } else {
      const char = e.key.toUpperCase();
      const isEnChar = /^[A-Z]$/.test(char);
      const isRuChar = /^[А-ЯЁ]$/.test(char);

      if (settings.language === 'EN' && isEnChar) handleChar(char);
      else if (settings.language === 'RU' && isRuChar) handleChar(char);
    }
  }, [gameState, settings, view, keyStatuses]); 

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);


  // --- Feature Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const rawWords = text.split(/[\n\s,]+/);
      const cleanedWords = rawWords
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
        .filter(w => w.length > 0);

      // Save dictionary to current profile
      setUserProfile(prev => ({
        ...prev,
        customDictionaryEn: cleanedWords
      }));

      // Immediately enable custom dictionary in settings
      setSettings(prev => ({
        ...prev,
        useCustomDictionary: true
      }));
    };
    reader.readAsText(file);
  };

  const fetchHint = () => {
    if (gameState.gameStatus !== 'playing') return;
    const currentDict = getDictionary();
    const hintWord = getAlgorithmicHint(gameState.secretWord, gameState.guesses, currentDict);
    setGameState(prev => ({ ...prev, hint: hintWord }));
  };

  // --- Render ---

  if (view === 'landing') {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-50 to-white flex items-center justify-center p-4">
        <div className="max-w-4xl w-full bg-white rounded-2xl shadow-xl overflow-hidden flex flex-col md:flex-row">

          {/* Left Side: Brand & Info */}
          <div className="md:w-2/5 bg-indigo-600 p-8 text-white flex flex-col justify-between">
            <div>
              <h1 className="text-4xl font-extrabold tracking-tight mb-2">
                ANN<span className="text-green-300">WORD</span>
              </h1>
              <p className="text-indigo-100 mb-6">
                Изучайте слова, тренируйте память и соревнуйтесь с самим собой.
              </p>

              <div className="bg-indigo-700/50 p-4 rounded-xl backdrop-blur-sm border border-indigo-500/30">
                <div className="flex items-center gap-2 mb-3">
                  <UserIcon />
                  <span className="font-bold">{userProfile.username}</span>
                </div>
                <div className="grid grid-cols-2 gap-4 text-center">
                  <div>
                    <div className="text-2xl font-bold">{userProfile.stats.gamesPlayed}</div>
                    <div className="text-xs text-indigo-200 uppercase tracking-wide">Игр</div>
                  </div>
                  <div>
                    <div className="text-2xl font-bold text-green-300">{userProfile.stats.gamesWon}</div>
                    <div className="text-xs text-indigo-200 uppercase tracking-wide">Побед</div>
                  </div>
                </div>
              </div>
            </div>

            <div className="mt-8 text-sm text-indigo-200">
               <p className="font-semibold mb-2">Ваши лучшие слова:</p>
               <div className="flex flex-wrap gap-1">
                 {Object.entries(userProfile.stats.wordsGuessed)
                   .sort(([, countA], [, countB]) => (countB as number) - (countA as number))
                   .slice(0, 5)
                   .map(([word]) => (
                     <span key={word} className="bg-indigo-500/50 px-2 py-0.5 rounded text-xs">{word}</span>
                 ))}
                 {Object.keys(userProfile.stats.wordsGuessed).length === 0 && <span>Пока нет данных</span>}
               </div>
            </div>
          </div>

          {/* Right Side: Settings & Start */}
          <div className="md:w-3/5 p-8 flex flex-col justify-center">
             <h2 className="text-2xl font-bold text-gray-800 mb-6">Настройки игры</h2>

             <div className="space-y-6">

               {/* Username Input */}
               <div>
                 <label className="block text-sm font-semibold text-gray-700 mb-2">Имя игрока</label>
                 <input 
                   type="text" 
                   value={settings.username}
                   onChange={(e) => setSettings(s => ({...s, username: e.target.value}))}
                   className="w-full px-4 py-2 bg-gray-50 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
                   placeholder="Введите ваше имя"
                 />
               </div>

               {/* Language */}
               <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Язык</label>
                  <div className="flex gap-4">
                    <label className={`flex-1 cursor-pointer border-2 rounded-xl p-3 flex items-center justify-center gap-2 transition ${settings.language === 'EN' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-200 hover:border-gray-300'}`}>
                      <input type="radio" name="lang" className="hidden" checked={settings.language === 'EN'} onChange={() => setSettings(s => ({...s, language: 'EN'}))} />
                      <span className="font-bold">English</span>
                    </label>
                    <label className={`flex-1 cursor-pointer border-2 rounded-xl p-3 flex items-center justify-center gap-2 transition ${settings.language === 'RU' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-200 hover:border-gray-300'}`}>
                      <input type="radio" name="lang" className="hidden" checked={settings.language === 'RU'} onChange={() => setSettings(s => ({...s, language: 'RU'}))} />
                      <span className="font-bold">Русский</span>
                    </label>
                  </div>
               </div>

               {/* Word Length */}
               <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Длина слова</label>
                  <div className="flex justify-between gap-2 bg-gray-100 p-1 rounded-lg">
                    {[4, 5, 6].map(len => (
                      <button
                        key={len}
                        onClick={() => setSettings(s => ({...s, wordLength: len as WordLength}))}
                        className={`flex-1 py-2 rounded-md font-bold text-sm transition ${settings.wordLength === len ? 'bg-white shadow text-indigo-600' : 'text-gray-500 hover:bg-gray-200'}`}
                      >
                        {len}
                      </button>
                    ))}
                  </div>
               </div>

               {/* Dictionary (EN only) */}
               {settings.language === 'EN' && (
                 <div className="bg-yellow-50 border border-yellow-100 rounded-xl p-4">
                    <div className="flex items-center justify-between mb-3">
                      <label className="text-sm font-bold text-yellow-800">Свой словарь</label>
                      <div className="flex items-center">
                        <input 
                          type="checkbox" 
                          id="useCustom"
                          checked={settings.useCustomDictionary}
                          onChange={(e) => setSettings(s => ({...s, useCustomDictionary: e.target.checked}))}
                          disabled={userProfile.customDictionaryEn.length === 0}
                          className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500 border-gray-300"
                        />
                        <label htmlFor="useCustom" className={`ml-2 text-sm ${userProfile.customDictionaryEn.length === 0 ? 'text-gray-400' : 'text-gray-700'}`}>
                          Включить ({userProfile.customDictionaryEn.length})
                        </label>
                      </div>
                    </div>

                    <input 
                      type="file" 
                      accept=".txt" 
                      onChange={handleFileUpload}
                      className="block w-full text-xs text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-yellow-100 file:text-yellow-700 hover:file:bg-yellow-200 cursor-pointer"
                    />
                    <p className="text-[10px] text-gray-400 mt-2">Поддерживаются .txt файлы</p>
                 </div>
               )}

               <button 
                onClick={startNewGame}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl text-lg shadow-lg hover:shadow-xl transition transform active:scale-[0.98] mt-4"
               >
                 Начать игру
               </button>
             </div>
          </div>
        </div>
      </div>
    );
  }

  // --- Game View ---
  return (
    <div className="flex flex-col h-screen items-center bg-gray-50 overflow-hidden relative">
      {/* Header */}
      <header className="w-full border-b bg-white p-4 flex justify-between items-center shadow-sm z-10">
        <button onClick={() => setView('landing')} className="p-2 hover:bg-gray-100 rounded-full text-gray-600 hover:text-indigo-600 transition" title="Домой">
          <HomeIcon />
        </button>
        <h1 className="text-2xl font-bold tracking-wider">
          ANN<span className="text-green-600">WORD</span>
        </h1>
        <div className="w-10"></div> {/* Spacer for balance */}
      </header>

      {/* Main Game Area */}
      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-lg p-4 overflow-y-auto">

        {/* Hint Section */}
        {settings.language === 'EN' && gameState.gameStatus === 'playing' && (
           <div className="w-full mb-4 flex flex-col items-center min-h-[3rem]">
             {!gameState.hint ? (
               <button 
                onClick={fetchHint}
                className="text-xs sm:text-sm bg-indigo-100 text-indigo-700 px-4 py-2 rounded-full font-semibold hover:bg-indigo-200 transition"
               >
                 💡 Подсказка (Слово)
               </button>
             ) : (
               <div className="bg-indigo-50 border border-indigo-200 text-indigo-800 p-3 rounded-lg text-sm text-center shadow-sm animate-fade-in w-full">
                 <span className="font-bold">Попробуйте ввести:</span> {gameState.hint}
               </div>
             )}
           </div>
        )}

        <Grid 
          guesses={gameState.guesses}
          currentGuess={gameState.currentGuess}
          secretWord={gameState.secretWord}
          wordLength={settings.wordLength}
          maxGuesses={MAX_GUESSES}
        />

        {/* Game Over Message */}
        {gameState.gameStatus !== 'playing' && (
          <div className="mt-4 p-4 bg-white rounded-lg shadow-md border text-center animate-bounce-in w-full max-w-sm">
             <h2 className="text-xl font-bold mb-2">
               {gameState.gameStatus === 'won' ? '🎉 Победа!' : '😔 Вы проиграли'}
             </h2>
             <p className="mb-4 text-gray-700">
               Загаданное слово: <span className="font-bold text-black">{gameState.secretWord}</span>
             </p>
             <button 
               onClick={startNewGame}
               className="bg-green-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-green-700 flex items-center justify-center gap-2 mx-auto w-full transition shadow-md"
             >
               <RefreshIcon /> Играть снова
             </button>
          </div>
        )}
      </main>

      {/* Keyboard Area */}
      <footer className="w-full bg-gray-100 pb-2 pt-2 border-t flex justify-center">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>
    </div>
  );
};

export default App;

import { UserProfile, UserStats } from "../types";

// --- MOCK SERVER IMPLEMENTATION ---
// В реальном проекте здесь были бы вызовы fetch() к вашему API.
// Сейчас мы имитируем работу сервера, используя localStorage как базу данных
// и добавляем искусственную задержку (latency), чтобы интерфейс реагировал как на реальный запрос.

const SIMULATED_NETWORK_DELAY = 600; // ms

const getStorageKey = (username: string) => `annword_server_db_${username.toLowerCase()}`;

export const userService = {
  /**
   * GET /api/users/:username
   * Загружает профиль пользователя с "сервера".
   */
  getUserProfile: async (username: string): Promise<UserProfile> => {
    return new Promise((resolve) => {
      setTimeout(() => {
        const key = getStorageKey(username);
        const data = localStorage.getItem(key);

        if (data) {
          resolve(JSON.parse(data));
        } else {
          // Если пользователя нет, сервер создает нового (или возвращает 404, тут мы создаем)
          const newProfile: UserProfile = {
            username,
            customDictionaryEn: [],
            stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
          };
          // Сохраняем "в базу"
          localStorage.setItem(key, JSON.stringify(newProfile));
          resolve(newProfile);
        }
      }, SIMULATED_NETWORK_DELAY);
    });
  },

  /**
   * POST /api/users/:username/stats
   * Обновляет статистику пользователя.
   */
  updateUserStats: async (username: string, newStats: UserStats): Promise<void> => {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        try {
          const key = getStorageKey(username);
          const data = localStorage.getItem(key);
          if (!data) throw new Error("User not found");

          const profile: UserProfile = JSON.parse(data);
          profile.stats = newStats;

          localStorage.setItem(key, JSON.stringify(profile));
          console.log(`[Server] Stats updated for ${username}`);
          resolve();
        } catch (e) {
          reject(e);
        }
      }, SIMULATED_NETWORK_DELAY / 2); // Быстрее чем полная загрузка
    });
  },

  /**
   * POST /api/users/:username/dictionary
   * Загружает пользовательский словарь.
   */
  updateUserDictionary: async (username: string, dictionary: string[]): Promise<void> => {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        try {
          const key = getStorageKey(username);
          const data = localStorage.getItem(key);
          if (!data) throw new Error("User not found");

          const profile: UserProfile = JSON.parse(data);
          profile.customDictionaryEn = dictionary;

          localStorage.setItem(key, JSON.stringify(profile));
          console.log(`[Server] Dictionary updated for ${username}. Size: ${dictionary.length}`);
          resolve();
        } catch (e) {
          reject(e);
        }
      }, SIMULATED_NETWORK_DELAY);
    });
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameSettings, GameState, CharStatus, UserProfile, WordLength } from './types';
import { DEFAULT_WORDS_EN, DEFAULT_WORDS_RU, MAX_GUESSES } from './constants';
import { Grid } from './components/Grid';
import { Keyboard } from './components/Keyboard';
import { getAlgorithmicHint } from './services/hintService';
import { userService } from './services/userService';

// --- Icons ---
const HomeIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
);
const RefreshIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"></path><path d="M16 21h5v-5"></path></svg>
);
const UserIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg>
);
const LoaderIcon = () => (
  <svg className="animate-spin" xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 1 1-6.219-8.56"></path></svg>
);

const App: React.FC = () => {
  // --- State ---
  const [view, setView] = useState<'landing' | 'game'>('landing');

  const [settings, setSettings] = useState<GameSettings>({
    language: 'EN',
    wordLength: 5,
    useCustomDictionary: false,
    username: 'Guest',
  });

  // Profile Data
  const [userProfile, setUserProfile] = useState<UserProfile>({
    username: 'Guest',
    customDictionaryEn: [],
    stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
  });

  // Loading States
  const [isLoadingProfile, setIsLoadingProfile] = useState(false);
  const [isUploadingDict, setIsUploadingDict] = useState(false);

  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    guesses: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });

  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  // --- Profile Management (Async) ---

  // Function to load profile from "server"
  const loadProfile = useCallback(async (username: string) => {
    setIsLoadingProfile(true);
    try {
      const profile = await userService.getUserProfile(username);
      setUserProfile(profile);

      // Auto-configure settings based on loaded profile
      if (profile.customDictionaryEn.length > 0) {
        setSettings(prev => ({ ...prev, useCustomDictionary: true }));
      } else {
        setSettings(prev => ({ ...prev, useCustomDictionary: false }));
      }
    } catch (error) {
      console.error("Failed to load profile", error);
    } finally {
      setIsLoadingProfile(false);
    }
  }, []);

  // Trigger load when username input loses focus or after a delay (debouncing could be used here)
  // For simplicity, we'll load when the user clicks a "Load/Login" button or initially
  useEffect(() => {
    loadProfile(settings.username);
  }, []); // Run once on mount for default Guest


  // --- Game Helpers ---

  const getDictionary = useCallback(() => {
    let pool: string[] = [];

    // 1. Choose Source
    if (settings.language === 'EN' && settings.useCustomDictionary && userProfile.customDictionaryEn.length > 0) {
      pool = userProfile.customDictionaryEn;
    } else {
      pool = settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU;
    }

    // 2. Filter by Length
    const filtered = pool.filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());

    // Fallback logic
    if (filtered.length === 0) {
      if (settings.useCustomDictionary) {
         const fallback = (settings.language === 'EN' ? DEFAULT_WORDS_EN : DEFAULT_WORDS_RU)
          .filter(w => w.length === settings.wordLength)
          .map(w => w.toUpperCase());
         return fallback;
      }
      return [];
    }
    return filtered;
  }, [settings.language, settings.useCustomDictionary, settings.wordLength, userProfile.customDictionaryEn]);

  const startNewGame = useCallback(() => {
    const words = getDictionary();
    if (words.length === 0) {
      setGameState(prev => ({ ...prev, error: "Слов с такими настройками не найдено.", gameStatus: 'lost' }));
      return;
    }

    const randomWord = words[Math.floor(Math.random() * words.length)];

    setGameState({
      secretWord: randomWord,
      guesses: [],
      currentGuess: '',
      gameStatus: 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: null,
    });
    setKeyStatuses({});
    setView('game');
  }, [getDictionary]);


  // --- Logic ---

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1) }));
  };

  const updateStats = async (won: boolean, word: string) => {
    // 1. Optimistic UI update
    const newStats = { ...userProfile.stats };
    newStats.gamesPlayed += 1;
    if (won) {
      newStats.gamesWon += 1;
      newStats.wordsGuessed[word] = (newStats.wordsGuessed[word] || 0) + 1;
    }

    setUserProfile(prev => ({ ...prev, stats: newStats }));

    // 2. Sync with "Server"
    try {
      await userService.updateUserStats(userProfile.username, newStats);
    } catch (e) {
      console.error("Failed to sync stats to server", e);
      // Here you might rollback the optimistic update if strict consistency is needed
    }
  };

  const handleEnter = () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) return;

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    // Update Key Statuses
    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      const currentStatus = newKeyStatuses[char];
      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    // Check Win/Loss
    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      updateStats(true, gameState.secretWord);
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      updateStats(false, gameState.secretWord);
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null 
    }));
  };

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (view !== 'game') return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;

    if (e.key === 'Enter') {
      handleEnter();
    } else if (e.key === 'Backspace') {
      handleDelete();
    } else {
      const char = e.key.toUpperCase();
      const isEnChar = /^[A-Z]$/.test(char);
      const isRuChar = /^[А-ЯЁ]$/.test(char);

      if (settings.language === 'EN' && isEnChar) handleChar(char);
      else if (settings.language === 'RU' && isRuChar) handleChar(char);
    }
  }, [gameState, settings, view, keyStatuses]); 

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);


  // --- Feature Handlers ---

  const handleUsernameBlur = () => {
    // When leaving the username field, load that user's profile
    if (settings.username !== userProfile.username) {
       loadProfile(settings.username);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploadingDict(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const text = event.target?.result as string;
      const rawWords = text.split(/[\n\s,]+/);
      const cleanedWords = rawWords
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
