import { CharStatus } from "../types";

// Helper to check if a word matches current constraints
const isValidCandidate = (
  candidate: string,
  guesses: string[],
  secretWord: string
): boolean => {
  // 1. Cannot be a word already guessed
  if (guesses.includes(candidate)) return false;

  const secretArr = secretWord.split('');
  const candidateArr = candidate.split('');

  // Robust solver logic:
  for (const guess of guesses) {
    // Analyze specific guess constraints against the candidate
    for (let j = 0; j < guess.length; j++) {
      const letter = guess[j];
      const statusInGuess = getStatus(secretWord, guess, j);

      if (statusInGuess === 'correct') {
        if (candidate[j] !== letter) return false;
      } else if (statusInGuess === 'present') {
        if (!candidate.includes(letter)) return false;
        if (candidate[j] === letter) return false; // Yellow means "not here"
      } else if (statusInGuess === 'absent') {
         // Gray logic simplified:
         // If a letter is gray, and it DOES NOT appear as green/yellow in the SAME guess, the candidate should not have it.
         const isAlsoGreenOrYellow = guess.split('').some((l, idx) => l === letter && idx !== j && (secretWord[idx] === l || secretWord.includes(l)));
         if (!isAlsoGreenOrYellow && candidate.includes(letter)) return false;
      }
    }
  }

  return true;
};

// Helper from Grid logic to determine status for calculation
const getStatus = (secret: string, guess: string, index: number): CharStatus => {
  const letter = guess[index];
  if (secret[index] === letter) return 'correct';

  // Handle duplicates for 'present' / 'absent' logic strictly
  // Count letter in secret
  let countInSecret = 0;
  for(const c of secret) if(c === letter) countInSecret++;

  // Count correct placements of this letter in guess
  let correctInGuess = 0;
  for(let i=0; i<guess.length; i++) if(guess[i] === letter && secret[i] === letter) correctInGuess++;

  // Count occurrences of this letter in guess up to this index (inclusive) that are NOT correct
  let seenSoFar = 0;
  for(let i=0; i<=index; i++) {
    if(guess[i] === letter && secret[i] !== letter) seenSoFar++;
  }

  const remainingAvailable = countInSecret - correctInGuess;

  if (secret.includes(letter) && seenSoFar <= remainingAvailable) return 'present';
  return 'absent';
};

export const getAlgorithmicHint = (
  secretWord: string,
  guesses: string[],
  dictionary: string[]
): string | null => {
  // Filter dictionary for potential candidates
  const candidates = dictionary.filter(word => 
    word !== secretWord && // Don't give the answer directly if possible
    isValidCandidate(word, guesses, secretWord)
  );

  if (candidates.length > 0) {
    // Return a random valid candidate
    return candidates[Math.floor(Math.random() * candidates.length)];
  }

  // Return null so the UI implies "No algorithmic hint available" (triggering AI fallback)
  return null;
};

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
// Note: In a real production app, ensure API_KEY is set. 
// If not set, we'll handle the error gracefully in the UI.

const ai = new GoogleGenAI({ apiKey });

export const generateHint = async (secretWord: string): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Cannot generate hint.");
  }

  const prompt = `
    Context: The secret word for a word-guessing game is "${secretWord}".
    Audience: School students (beginners) learning English.
    Task: Create a VERY SIMPLE sentence where this word fits perfectly.
    Requirement 1: Use only basic, high-frequency vocabulary suitable for children.
    Requirement 2: Replace the secret word (and only the secret word) with "_______" (underscores).
    Requirement 3: Do not mention the secret word itself anywhere in the output.
    Example if word is "APPLE": "I eat a red _______."
    Example if word is "READ": "I _______ a book every day."
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    const text = response.text;
    if (!text) return "Не удалось сгенерировать подсказку.";
    return text.trim();
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to contact AI service.");
  }
};

