const App: React.FC = () => {
  // --- State ---
  const [view, setView] = useState<ViewState>('landing');
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [tempUsername, setTempUsername] = useState('');

  const [settings, setSettings] = useState<GameSettings>({
    language: 'EN',
    wordLength: 5,
    useCustomDictionary: false,
    dictionarySource: 'builtin',
    difficulty: 'ALL',
    username: 'Guest',
  });

  // Profile Data
  const [userProfile, setUserProfile] = useState<UserProfile>({
    username: 'Guest',
    customDictionaryEn: [],
    stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
  });

  // Loading States
  const [isLoadingProfile, setIsLoadingProfile] = useState(false);
  const [isUploadingDict, setIsUploadingDict] = useState(false);
  const [shakeRowIndex, setShakeRowIndex] = useState<number | null>(null);

  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    secretWordData: null,
    guesses: [],
    history: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });

  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  const historyScrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll history
  useEffect(() => {
    if (historyScrollRef.current) {
      historyScrollRef.current.scrollLeft = historyScrollRef.current.scrollWidth;
    }
  }, [gameState.history]);

  // --- Profile Management (Async) ---

  const loadProfile = useCallback(async (username: string) => {
    setIsLoadingProfile(true);
    try {
      const profile = await userService.getUserProfile(username);
      setUserProfile(profile);
      // If user has a custom dict, we don't automatically switch to it, we let them choose in setup
    } catch (error) {
      console.error("Failed to load profile", error);
    } finally {
      setIsLoadingProfile(false);
    }
  }, []);

  useEffect(() => {
    loadProfile(settings.username);
  }, []); 

  const handleLoginSubmit = () => {
    if (tempUsername.trim()) {
      setSettings(prev => ({ ...prev, username: tempUsername }));
      loadProfile(tempUsername);
      setShowLoginModal(false);
    }
  };


  // --- Game Helpers ---

  // 1. POOL FOR SECRET WORD
  const getSecretWordPool = useCallback(() => {
    if (settings.language === 'EN') {
       if (settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length > 0) {
          // Custom dictionary are plain strings.
          return userProfile.customDictionaryEn.map(w => ({ word: w, translation: '', level: 'Custom' }));
       }

       // Built-in Dictionary with Difficulty Filter
       let pool = COMMON_WORDS_EN;
       if (settings.difficulty !== 'ALL') {
         pool = pool.filter(w => w.level === settings.difficulty);
       }
       return pool;
    } else {
       // Russian dictionary
       return COMMON_WORDS_RU;
    }
  }, [settings.language, settings.dictionarySource, settings.difficulty, userProfile.customDictionaryEn]);

  // 2. POOL FOR VALIDATION
  const getValidationPool = useCallback(() => {
    const basePool = settings.language === 'EN' ? ALL_WORDS_EN : ALL_WORDS_RU;
    let combinedPool = basePool.filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());

    if (settings.language === 'EN' && userProfile.customDictionaryEn.length > 0) {
       const customFiltered = userProfile.customDictionaryEn
         .filter(w => w.length === settings.wordLength)
         .map(w => w.toUpperCase());
       combinedPool = Array.from(new Set([...combinedPool, ...customFiltered]));
    }

    return combinedPool;
  }, [settings.language, settings.wordLength, userProfile.customDictionaryEn]);


  const startNewGame = useCallback(() => {
    const rawPool = getSecretWordPool();

    // Filter by length
    let filteredPool: Array<string | EnrichedWord> = [];

    if (rawPool.length > 0 && typeof rawPool[0] === 'string') {
        filteredPool = (rawPool as string[]).filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());
    } else {
        filteredPool = (rawPool as EnrichedWord[]).filter(w => w.word.length === settings.wordLength);
    }

    if (filteredPool.length === 0) {
      let msg = "Слов с такими настройками не найдено.";
      if (settings.language === 'EN' && settings.dictionarySource === 'custom') {
        msg = `В вашем словаре нет слов длиной ${settings.wordLength}.`;
      } else if (settings.language === 'EN') {
        msg = `Нет слов уровня ${settings.difficulty} длиной ${settings.wordLength}.`;
      }
      setGameState(prev => ({ ...prev, error: msg, gameStatus: 'lost' }));
      // Don't switch view if error, stay on setup or switch to game to show error?
      // Better to show error in Game View or prevent start. 
      // Current architecture renders error in Game View.
    }

    // If we have words, pick one
    let secretWord = '';
    let secretWordData: EnrichedWord | null = null;

    if (filteredPool.length > 0) {
      const randomEntry = filteredPool[Math.floor(Math.random() * filteredPool.length)];
      if (typeof randomEntry === 'string') {
          secretWord = randomEntry;
      } else {
          secretWord = randomEntry.word;
          secretWordData = randomEntry;
      }
    }

    setGameState({
      secretWord: secretWord,
      secretWordData: secretWordData,
      guesses: [],
      history: [],
      currentGuess: '',
      gameStatus: filteredPool.length === 0 ? 'lost' : 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: filteredPool.length === 0 ? "Нет слов" : null,
    });
    setKeyStatuses({});
    setView('game');
  }, [getSecretWordPool, settings.wordLength, settings.language, settings.dictionarySource, settings.difficulty]);


  // --- Logic ---

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char, error: null }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1), error: null }));
  };

  const updateStats = async (won: boolean, word: string) => {
    const newStats = { ...userProfile.stats };
    newStats.gamesPlayed += 1;
    if (won) {
      newStats.gamesWon += 1;
      newStats.wordsGuessed[word] = (newStats.wordsGuessed[word] || 0) + 1;
    }

    setUserProfile(prev => ({ ...prev, stats: newStats }));

    try {
      await userService.updateUserStats(userProfile.username, newStats);
    } catch (e) {
      console.error("Failed to sync stats to server", e);
    }
  };

  const triggerShake = () => {
    setShakeRowIndex(gameState.rowIndex);
    setTimeout(() => setShakeRowIndex(null), 600);
  };

  const handleEnter = () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) {
       setGameState(prev => ({ ...prev, error: "Недостаточно букв" }));
       triggerShake();
       return;
    }

    const validWords = getValidationPool();
    if (!validWords.includes(gameState.currentGuess)) {
      setGameState(prev => ({ ...prev, error: "Такого слова нет в словаре" }));
      triggerShake();
      return;
    }

    // --- NEW LOGIC: FIND TRANSLATION ---
    const wordEntry = COMMON_WORDS_EN.find(w => w.word === gameState.currentGuess);
    const translation = wordEntry ? wordEntry.translation : null;
    const newHistoryItem = { word: gameState.currentGuess, translation };
    const newHistory = [...gameState.history, newHistoryItem];

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      const currentStatus = newKeyStatuses[char];
      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      updateStats(true, gameState.secretWord);
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      updateStats(false, gameState.secretWord);
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      history: newHistory,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null,
      error: null
    }));
  };

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (view !== 'game') return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;

    if (e.key === 'Enter') {
      handleEnter();
    } else if (e.key === 'Backspace') {
      handleDelete();
    } else {
      const char = e.key.toUpperCase();
      const isEnChar = /^[A-Z]$/.test(char);
      const isRuChar = /^[А-ЯЁ]$/.test(char);

      if (settings.language === 'EN' && isEnChar) handleChar(char);
      else if (settings.language === 'RU' && isRuChar) handleChar(char);
    }
  }, [gameState, settings, view, keyStatuses, userProfile]); 

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);


  // --- Feature Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploadingDict(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const text = event.target?.result as string;
      const rawWords = text.split(/[\n\s,]+/);
      const cleanedWords = rawWords
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
        .filter(w => w.length > 0);

      setUserProfile(prev => ({
        ...prev,
        customDictionaryEn: cleanedWords
      }));

      try {
        await userService.updateUserDictionary(settings.username, cleanedWords);
      } catch (e) {
        console.error("Failed to upload dictionary", e);
      } finally {
        setIsUploadingDict(false);
      }
    };
    reader.readAsText(file);
  };

  const fetchHint = async () => {
    if (gameState.gameStatus !== 'playing') return;

    // Calculate which dictionary to use for the hint pool
    let hintPool: string[] = [];

    if (settings.language === 'EN') {
      // 1. Custom Dictionary Preference
      if (settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length > 0) {
        hintPool = userProfile.customDictionaryEn;
      } else {
        // 2. Built-in Dictionary Fallback: Use 'A1' (easiest) category
        // We filter the ENRICHED dictionary for A1 words and map to simple strings
        hintPool = COMMON_WORDS_EN
          .filter(w => w.level === 'A1')
          .map(w => w.word);
      }
    } else {
      // Russian dictionary
      hintPool = COMMON_WORDS_RU;
    }

    // Filter potential hints by current word length
    hintPool = hintPool.filter(w => w.length === settings.wordLength);

    setGameState(prev => ({ ...prev, loadingHint: true }));

    // Simulate a brief "thinking" delay for UX consistency
    setTimeout(() => {
      const bestWord = getBestEliminationHint(
        gameState.secretWord, 
        gameState.guesses, 
        hintPool
      );

      const hintText = bestWord 
        ? `Попробуйте слово: ${bestWord}` 
        : "Нет подходящих слов для подсказки.";

      setGameState(prev => ({ 
        ...prev, 
        hint: hintText, 
        loadingHint: false 
      }));
    }, 500);
  };

  // --- Views ---

  const renderLanding = () => (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-indigo-50 to-white p-4">
      {/* Login Modal */}
      {showLoginModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl p-6 shadow-2xl w-full max-w-sm">
            <h3 className="text-xl font-bold mb-4">Как вас зовут?</h3>
            <input 
              autoFocus
              type="text" 
              value={tempUsername}
              onChange={(e) => setTempUsername(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleLoginSubmit()}
              placeholder="Ваше имя"
              className="w-full border-2 border-gray-200 rounded-lg p-3 mb-4 focus:border-indigo-500 focus:outline-none"
            />
            <div className="flex gap-2">
              <button onClick={() => setShowLoginModal(false)} className="flex-1 py-2 text-gray-500 hover:bg-gray-100 rounded-lg">Отмена</button>
              <button onClick={handleLoginSubmit} className="flex-1 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">Войти</button>
            </div>
          </div>
        </div>
      )}

      {/* User Header */}
      <div className="absolute top-4 right-4 sm:top-8 sm:right-8">
        {settings.username === 'Guest' ? (
          <button 
            onClick={() => setShowLoginModal(true)}
            className="flex items-center gap-2 text-indigo-600 hover:text-indigo-800 font-semibold bg-white px-4 py-2 rounded-full shadow-sm hover:shadow transition"
          >
            <LoginIcon /> Войти
          </button>
        ) : (
          <button 
            onClick={() => setView('profile')}
            className="flex items-center gap-2 text-indigo-900 hover:text-indigo-700 font-bold bg-white px-4 py-2 rounded-full shadow-sm hover:shadow transition"
          >
            <UserIcon /> Привет, {settings.username}
          </button>
        )}
      </div>

      <div className="text-center mb-12">
        <h1 className="text-6xl font-black tracking-tighter text-indigo-900 mb-2">
          ANN<span className="text-green-500">WORD</span>
        </h1>
        <p className="text-gray-500 text-lg">Тренируй мозг, учи слова</p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 w-full max-w-2xl">
        <button 
          onClick={() => { setSettings(s => ({ ...s, language: 'RU' })); setView('setup'); }}
          className="group relative bg-white hover:bg-red-50 border-2 border-gray-100 hover:border-red-200 rounded-2xl p-8 shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1"
        >
          <div className="text-4xl mb-3">🇷🇺</div>
          <h2 className="text-2xl font-bold text-gray-800 group-hover:text-red-600">Русский</h2>
          <p className="text-gray-400 text-sm mt-2">Базовый словарь</p>
        </button>

        <button 
          onClick={() => { setSettings(s => ({ ...s, language: 'EN' })); setView('setup'); }}
          className="group relative bg-white hover:bg-blue-50 border-2 border-gray-100 hover:border-blue-200 rounded-2xl p-8 shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1"
        >
          <div className="text-4xl mb-3">🇬🇧</div>
          <h2 className="text-2xl font-bold text-gray-800 group-hover:text-blue-600">English</h2>
          <p className="text-gray-400 text-sm mt-2">Уровни A1-C1 или свой словарь</p>
        </button>
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center p-6">
      <header className="w-full max-w-2xl flex items-center mb-8">
        <button onClick={() => setView('landing')} className="p-2 hover:bg-gray-200 rounded-full transition">
          <BackIcon />
        </button>
        <h2 className="text-2xl font-bold ml-4">Профиль игрока</h2>
      </header>

      <div className="bg-white rounded-2xl shadow-lg p-8 w-full max-w-2xl">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600">
            <UserIcon />
          </div>
          <div>
            <h3 className="text-2xl font-bold text-gray-900">{userProfile.username}</h3>
            <p className="text-gray-500">Статистика игр</p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-8">
          <div className="bg-gray-50 p-4 rounded-xl text-center">
            <div className="text-3xl font-black text-gray-900">{userProfile.stats.gamesPlayed}</div>
            <div className="text-sm text-gray-500 uppercase tracking-wide">Всего игр</div>
          </div>
          <div className="bg-green-50 p-4 rounded-xl text-center">
            <div className="text-3xl font-black text-green-600">{userProfile.stats.gamesWon}</div>
            <div className="text-sm text-green-600 uppercase tracking-wide">Побед</div>
          </div>
        </div>

        <h4 className="font-bold text-gray-800 mb-4">Лучшие слова</h4>
        <div className="flex flex-wrap gap-2">
          {Object.entries(userProfile.stats.wordsGuessed)
            .sort(([, a], [, b]) => b - a)
            .slice(0, 10)
            .map(([word, count]) => (
              <span key={word} className="px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full text-sm font-medium border border-indigo-100">
                {word} <span className="text-indigo-400 text-xs ml-1">x{count}</span>
              </span>
            ))}
          {Object.keys(userProfile.stats.wordsGuessed).length === 0 && (
            <p className="text-gray-400 italic">Пока нет угаданных слов</p>
          )}
        </div>
      </div>
    </div>
  );

  const renderSetup = () => (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4">
      <div className="bg-white rounded-3xl shadow-xl w-full max-w-md overflow-hidden">
        <div className="bg-indigo-600 p-6 text-white flex items-center relative">
          <button onClick={() => setView('landing')} className="absolute left-4 p-2 hover:bg-white/20 rounded-full transition">
            <BackIcon />
          </button>
          <h2 className="text-xl font-bold w-full text-center">
            Настройка игры ({settings.language})
          </h2>
        </div>

        <div className="p-6 space-y-8">

          {/* ENGLISH SPECIFIC: Source Selection */}
          {settings.language === 'EN' && (
            <div>
              <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Источник слов</label>
              <div className="flex bg-gray-100 p-1 rounded-xl">
                <button 
                  onClick={() => setSettings(s => ({ ...s, dictionarySource: 'builtin', useCustomDictionary: false }))}
                  className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition ${settings.dictionarySource === 'builtin' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  Школьный
                </button>
                <button 
                  onClick={() => setSettings(s => ({ ...s, dictionarySource: 'custom', useCustomDictionary: true }))}
                  className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition ${settings.dictionarySource === 'custom' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  Мой словарь
                </button>
              </div>
            </div>
          )}

          {/* ENGLISH BUILT-IN: Difficulty */}
          {settings.language === 'EN' && settings.dictionarySource === 'builtin' && (
            <div className="animate-fade-in">
              <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Сложность</label>
              <div className="grid grid-cols-4 gap-2">
                {(['A1', 'A2', 'B1', 'B2', 'C1', 'ALL'] as DifficultyLevel[]).map(level => (
                  <button
                    key={level}
                    onClick={() => setSettings(s => ({ ...s, difficulty: level }))}
                    className={`py-2 rounded-lg text-sm font-bold border-2 transition ${
                      settings.difficulty === level 
                        ? 'border-indigo-500 bg-indigo-50 text-indigo-700' 
                        : 'border-transparent bg-gray-100 text-gray-500 hover:bg-gray-200'
                    }`}
                  >
                    {level === 'ALL' ? 'Все' : level}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* ENGLISH CUSTOM: Upload */}
          {settings.language === 'EN' && settings.dictionarySource === 'custom' && (
            <div className="animate-fade-in bg-yellow-50 border border-yellow-100 rounded-xl p-4">
              <label className="block text-sm font-bold text-yellow-800 mb-2">Загрузить файл (.txt)</label>
              {isUploadingDict ? (
                 <div className="flex items-center gap-2 text-sm text-yellow-700 animate-pulse py-2">
                   <LoaderIcon /> Загрузка...
                 </div>
              ) : (
                <input 
                  type="file" 
                  accept=".txt" 
                  onChange={handleFileUpload}
                  className="block w-full text-xs text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-yellow-200 file:text-yellow-800 hover:file:bg-yellow-300 cursor-pointer"
                />
              )}
              <p className="text-xs text-yellow-600/70 mt-2">
                Текущий словарь: {userProfile.customDictionaryEn.length > 0 ? `${userProfile.customDictionaryEn.length} слов` : 'Пусто'}
              </p>
            </div>
          )}

          {/* COMMON: Word Length */}
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Длина слова</label>
            <div className="flex gap-4">
              {[4, 5, 6].map(len => (
                <button
                  key={len}
                  onClick={() => setSettings(s => ({...s, wordLength: len as WordLength}))}
                  className={`flex-1 py-4 rounded-xl font-black text-xl border-2 transition transform active:scale-95 ${
                    settings.wordLength === len 
                      ? 'border-indigo-600 bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
                      : 'border-gray-200 bg-white text-gray-400 hover:border-gray-300'
                  }`}
                >
                  {len}
                </button>
              ))}
            </div>
          </div>

          <button 
            onClick={startNewGame}
            disabled={settings.language === 'EN' && settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length === 0}
            className="w-full bg-green-500 hover:bg-green-600 disabled:bg-gray-300 text-white font-bold py-4 rounded-xl text-lg shadow-xl shadow-green-100 transition transform active:scale-[0.98] mt-8"
          >
            Играть
          </button>
        </div>
      </div>
    </div>
  );

  // --- Main Switch ---

  if (view === 'landing') return renderLanding();
  if (view === 'profile') return renderProfile();
  if (view === 'setup') return renderSetup();

  // --- Game View ---
  return (
    <div className="flex flex-col h-screen items-center bg-gray-50 overflow-hidden relative">
      <header className="w-full border-b bg-white p-4 flex justify-between items-center shadow-sm z-10 shrink-0">
        <button onClick={() => setView('landing')} className="p-2 hover:bg-gray-100 rounded-full text-gray-600 hover:text-indigo-600 transition" title="Домой">
          <HomeIcon />
        </button>
        <h1 className="text-2xl font-bold tracking-wider">
          ANN<span className="text-green-600">WORD</span>
        </h1>
        <div className="w-10"></div>
      </header>

      {/* Error Toast */}
      <div className={`absolute top-20 z-50 transition-all duration-300 ${gameState.error ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}`}>
        <div className="bg-black text-white px-4 py-2 rounded-md font-bold shadow-lg">
          {gameState.error}
        </div>
      </div>

      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-lg p-2 overflow-hidden h-full">

        {/* --- English specific: Translation History Ticker & Hints --- */}
        {settings.language === 'EN' && gameState.gameStatus === 'playing' && (
           <div className="w-full mb-2 shrink-0 flex flex-col items-center justify-end gap-2">

             {/* History Ticker */}
             {gameState.history.length > 0 && (
               <div 
                 ref={historyScrollRef}
                 className="w-full overflow-x-auto whitespace-nowrap scrollbar-hide py-2 px-2 flex gap-2"
               >
                 {gameState.history.map((item, idx) => (
                   <div key={idx} className="inline-flex items-center bg-white border border-indigo-100 rounded-lg shadow-sm px-3 py-1.5 animate-bounce-in">
                     <span className="font-bold text-gray-800 text-sm">{item.word}</span>
                     {item.translation && (
                       <>
                         <span className="mx-1.5 text-gray-300">|</span>
                         <span className="text-indigo-600 text-sm">{item.translation}</span>
                       </>
                     )}
                   </div>
                 ))}
               </div>
             )}

             {/* Hint Button */}
             {!gameState.hint && !gameState.loadingHint ? (
               <button 
                onClick={fetchHint}
                className="text-xs sm:text-sm bg-indigo-50 border border-indigo-100 text-indigo-700 px-4 py-2 rounded-full font-semibold hover:bg-indigo-100 transition shadow-sm"
               >
                 💡 Подсказка
               </button>
             ) : gameState.loadingHint ? (
               <div className="bg-indigo-50 border border-indigo-100 text-indigo-500 px-4 py-2 rounded-full text-xs font-semibold flex items-center gap-2">
                 <LoaderIcon /> Думаю...
               </div>
             ) : (
               <div className="bg-indigo-50 border border-indigo-200 text-indigo-800 p-3 rounded-lg text-sm text-center shadow-sm animate-fade-in w-full">
                 <span className="font-bold">Подсказка:</span> {gameState.hint}
               </div>
             )}
           </div>
        )}

        {/* Grid Container */}
        <div className="flex-grow flex items-center justify-center w-full max-h-[65vh]">
          <Grid 
            guesses={gameState.guesses}
            currentGuess={gameState.currentGuess}
            secretWord={gameState.secretWord}
            wordLength={settings.wordLength}
            maxGuesses={MAX_GUESSES}
            shakeRowIndex={shakeRowIndex}
          />
        </div>

        {gameState.gameStatus !== 'playing' && (
          <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-40 p-4 bg-white/95 backdrop-blur rounded-lg shadow-2xl border text-center animate-bounce-in w-11/12 max-w-sm">
             <h2 className="text-xl font-bold mb-2">
               {gameState.gameStatus === 'won' ? '🎉 Победа!' : '😔 Вы проиграли'}
             </h2>
             <p className="mb-2 text-gray-700">
               Загаданное слово: <span className="font-bold text-black text-lg">{gameState.secretWord}</span>
             </p>
             {/* Show Translation and Level if available */}
             {gameState.secretWordData && (
                <div className="mb-4 text-sm">
                  <span className="block text-gray-500">Перевод: <span className="text-indigo-600 font-semibold">{gameState.secretWordData.translation}</span></span>
                  <span className="block text-gray-500 text-xs mt-1">Уровень: <span className="bg-gray-200 px-1.5 py-0.5 rounded text-gray-700 font-bold">{gameState.secretWordData.level}</span></span>
                </div>
             )}
             <div className="flex gap-2 justify-center">
                <button 
                  onClick={() => setView('landing')}
                  className="bg-gray-100 text-gray-700 px-4 py-3 rounded-lg font-bold hover:bg-gray-200 transition"
                >
                  Меню
                </button>
                <button 
                  onClick={startNewGame}
                  className="bg-green-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-green-700 flex items-center justify-center gap-2 transition shadow-md"
                >
                  <RefreshIcon /> Играть снова
                </button>
             </div>
          </div>
        )}
      </main>

      <footer className="w-full bg-gray-100 pb-4 pt-2 border-t flex justify-center shrink-0">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameSettings, GameState, CharStatus, UserProfile, WordLength, EnrichedWord, ViewState, DictionarySource, DifficultyLevel } from './types';
import { 
  COMMON_WORDS_EN, COMMON_WORDS_RU, 
  ALL_WORDS_EN, ALL_WORDS_RU,
  MAX_GUESSES 
} from './constants';
import { Grid } from './components/Grid';
import { Keyboard } from './components/Keyboard';
import { getBestEliminationHint } from './services/hintService';
import { userService } from './services/userService';

// --- Icons ---
const HomeIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
);
const RefreshIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"></path><path d="M16 21h5v-5"></path></svg>
);
const UserIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg>
);
const LoaderIcon = () => (
  <svg className="animate-spin" xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 1 1-6.219-8.56"></path></svg>
);
const BackIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>
);
const LoginIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4"></path><polyline points="10 17 15 12 10 7"></polyline><line x1="15" y1="12" x2="3" y2="12"></line></svg>
);
const TranslateIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m5 8 6 6"></path><path d="m4 14 6-6 2-3"></path><path d="M2 5h12"></path><path d="M7 2h1"></path><path d="m22 22-5-10-5 10"></path><path d="M14 18h6"></path></svg>
);

const App: React.FC = () => {
  // --- State ---
  const [view, setView] = useState<ViewState>('landing');
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [tempUsername, setTempUsername] = useState('');

  const [settings, setSettings] = useState<GameSettings>({
    language: 'EN',
    wordLength: 5,
    useCustomDictionary: false,
    dictionarySource: 'builtin',
    difficulty: 'ALL',
    username: 'Guest',
  });

  // Profile Data
  const [userProfile, setUserProfile] = useState<UserProfile>({
    username: 'Guest',
    customDictionaryEn: [],
    stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} }
  });

  // Loading States
  const [isLoadingProfile, setIsLoadingProfile] = useState(false);
  const [isUploadingDict, setIsUploadingDict] = useState(false);
  const [shakeRowIndex, setShakeRowIndex] = useState<number | null>(null);

  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    secretWordData: null,
    guesses: [],
    history: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });

  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  const historyScrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll history
  useEffect(() => {
    if (historyScrollRef.current) {
      historyScrollRef.current.scrollLeft = historyScrollRef.current.scrollWidth;
    }
  }, [gameState.history]);

  // --- Profile Management (Async) ---

  const loadProfile = useCallback(async (username: string) => {
    setIsLoadingProfile(true);
    try {
      const profile = await userService.getUserProfile(username);
      setUserProfile(profile);
      // If user has a custom dict, we don't automatically switch to it, we let them choose in setup
    } catch (error) {
      console.error("Failed to load profile", error);
    } finally {
      setIsLoadingProfile(false);
    }
  }, []);

  useEffect(() => {
    loadProfile(settings.username);
  }, []); 

  const handleLoginSubmit = () => {
    if (tempUsername.trim()) {
      setSettings(prev => ({ ...prev, username: tempUsername }));
      loadProfile(tempUsername);
      setShowLoginModal(false);
    }
  };


  // --- Game Helpers ---

  // 1. POOL FOR SECRET WORD
  const getSecretWordPool = useCallback(() => {
    if (settings.language === 'EN') {
       if (settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length > 0) {
          // Custom dictionary are plain strings.
          return userProfile.customDictionaryEn.map(w => ({ word: w, translation: '', level: 'Custom' }));
       }

       // Built-in Dictionary with Difficulty Filter
       let pool = COMMON_WORDS_EN;
       if (settings.difficulty !== 'ALL') {
         pool = pool.filter(w => w.level === settings.difficulty);
       }
       return pool;
    } else {
       // Russian dictionary
       return COMMON_WORDS_RU;
    }
  }, [settings.language, settings.dictionarySource, settings.difficulty, userProfile.customDictionaryEn]);

  // 2. POOL FOR VALIDATION
  const getValidationPool = useCallback(() => {
    const basePool = settings.language === 'EN' ? ALL_WORDS_EN : ALL_WORDS_RU;
    let combinedPool = basePool.filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());

    if (settings.language === 'EN' && userProfile.customDictionaryEn.length > 0) {
       const customFiltered = userProfile.customDictionaryEn
         .filter(w => w.length === settings.wordLength)
         .map(w => w.toUpperCase());
       combinedPool = Array.from(new Set([...combinedPool, ...customFiltered]));
    }

    return combinedPool;
  }, [settings.language, settings.wordLength, userProfile.customDictionaryEn]);


  const startNewGame = useCallback(() => {
    const rawPool = getSecretWordPool();

    // Filter by length
    let filteredPool: Array<string | EnrichedWord> = [];

    if (rawPool.length > 0 && typeof rawPool[0] === 'string') {
        filteredPool = (rawPool as string[]).filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());
    } else {
        filteredPool = (rawPool as EnrichedWord[]).filter(w => w.word.length === settings.wordLength);
    }

    if (filteredPool.length === 0) {
      let msg = "Слов с такими настройками не найдено.";
      if (settings.language === 'EN' && settings.dictionarySource === 'custom') {
        msg = `В вашем словаре нет слов длиной ${settings.wordLength}.`;
      } else if (settings.language === 'EN') {
        msg = `Нет слов уровня ${settings.difficulty} длиной ${settings.wordLength}.`;
      }
      setGameState(prev => ({ ...prev, error: msg, gameStatus: 'lost' }));
      // Don't switch view if error, stay on setup or switch to game to show error?
      // Better to show error in Game View or prevent start. 
      // Current architecture renders error in Game View.
    }

    // If we have words, pick one
    let secretWord = '';
    let secretWordData: EnrichedWord | null = null;

    if (filteredPool.length > 0) {
      const randomEntry = filteredPool[Math.floor(Math.random() * filteredPool.length)];
      if (typeof randomEntry === 'string') {
          secretWord = randomEntry;
      } else {
          secretWord = randomEntry.word;
          secretWordData = randomEntry;
      }
    }

    setGameState({
      secretWord: secretWord,
      secretWordData: secretWordData,
      guesses: [],
      history: [],
      currentGuess: '',
      gameStatus: filteredPool.length === 0 ? 'lost' : 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: filteredPool.length === 0 ? "Нет слов" : null,
    });
    setKeyStatuses({});
    setView('game');
  }, [getSecretWordPool, settings.wordLength, settings.language, settings.dictionarySource, settings.difficulty]);


  // --- Logic ---

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char, error: null }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1), error: null }));
  };

  const updateStats = async (won: boolean, word: string) => {
    const newStats = { ...userProfile.stats };
    newStats.gamesPlayed += 1;
    if (won) {
      newStats.gamesWon += 1;
      newStats.wordsGuessed[word] = (newStats.wordsGuessed[word] || 0) + 1;
    }

    setUserProfile(prev => ({ ...prev, stats: newStats }));

    try {
      await userService.updateUserStats(userProfile.username, newStats);
    } catch (e) {
      console.error("Failed to sync stats to server", e);
    }
  };

  const triggerShake = () => {
    setShakeRowIndex(gameState.rowIndex);
    setTimeout(() => setShakeRowIndex(null), 600);
  };

  const handleEnter = () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) {
       setGameState(prev => ({ ...prev, error: "Недостаточно букв" }));
       triggerShake();
       return;
    }

    const validWords = getValidationPool();
    if (!validWords.includes(gameState.currentGuess)) {
      setGameState(prev => ({ ...prev, error: "Такого слова нет в словаре" }));
      triggerShake();
      return;
    }

    // --- NEW LOGIC: FIND TRANSLATION ---
    const wordEntry = COMMON_WORDS_EN.find(w => w.word === gameState.currentGuess);
    const translation = wordEntry ? wordEntry.translation : null;
    const newHistoryItem = { word: gameState.currentGuess, translation };
    const newHistory = [...gameState.history, newHistoryItem];

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      const currentStatus = newKeyStatuses[char];
      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      updateStats(true, gameState.secretWord);
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      updateStats(false, gameState.secretWord);
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      history: newHistory,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null,
      error: null
    }));
  };

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (view !== 'game') return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;

    if (e.key === 'Enter') {
      handleEnter();
    } else if (e.key === 'Backspace') {
      handleDelete();
    } else {
      const char = e.key.toUpperCase();
      const isEnChar = /^[A-Z]$/.test(char);
      const isRuChar = /^[А-ЯЁ]$/.test(char);

      if (settings.language === 'EN' && isEnChar) handleChar(char);
      else if (settings.language === 'RU' && isRuChar) handleChar(char);
    }
  }, [gameState, settings, view, keyStatuses, userProfile]); 

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);


  // --- Feature Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploadingDict(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const text = event.target?.result as string;
      const rawWords = text.split(/[\n\s,]+/);
      const cleanedWords = rawWords
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
        .filter(w => w.length > 0);

      setUserProfile(prev => ({
        ...prev,
        customDictionaryEn: cleanedWords
      }));

      try {
        await userService.updateUserDictionary(settings.username, cleanedWords);
      } catch (e) {
        console.error("Failed to upload dictionary", e);
      } finally {
        setIsUploadingDict(false);
      }
    };
    reader.readAsText(file);
  };

  const fetchHint = async () => {
    if (gameState.gameStatus !== 'playing') return;

    // Calculate which dictionary to use for the hint pool
    let hintPool: string[] = [];

    if (settings.language === 'EN') {
      // 1. Custom Dictionary Preference
      if (settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length > 0) {
        hintPool = userProfile.customDictionaryEn;
      } else {
        // 2. Built-in Dictionary Fallback: Use 'A1' (easiest) category
        // We filter the ENRICHED dictionary for A1 words and map to simple strings
        hintPool = COMMON_WORDS_EN
          .filter(w => w.level === 'A1')
          .map(w => w.word);
      }
    } else {
      // Russian dictionary
      hintPool = COMMON_WORDS_RU;
    }

    // Filter potential hints by current word length
    hintPool = hintPool.filter(w => w.length === settings.wordLength);

    setGameState(prev => ({ ...prev, loadingHint: true }));

    // Simulate a brief "thinking" delay for UX consistency
    setTimeout(() => {
      const bestWord = getBestEliminationHint(
        gameState.secretWord, 
        gameState.guesses, 
        hintPool
      );

      const hintText = bestWord 
        ? `Попробуйте слово: ${bestWord}` 
        : "Нет подходящих слов для подсказки.";

      setGameState(prev => ({ 
        ...prev, 
        hint: hintText, 
        loadingHint: false 
      }));
    }, 500);
  };

  // --- Views ---

  const renderLanding = () => (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-indigo-50 to-white p-4">
      {/* Login Modal */}
      {showLoginModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl p-6 shadow-2xl w-full max-w-sm">
            <h3 className="text-xl font-bold mb-4">Как вас зовут?</h3>
            <input 
              autoFocus
              type="text" 
              value={tempUsername}
              onChange={(e) => setTempUsername(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleLoginSubmit()}
              placeholder="Ваше имя"
              className="w-full border-2 border-gray-200 rounded-lg p-3 mb-4 focus:border-indigo-500 focus:outline-none"
            />
            <div className="flex gap-2">
              <button onClick={() => setShowLoginModal(false)} className="flex-1 py-2 text-gray-500 hover:bg-gray-100 rounded-lg">Отмена</button>
              <button onClick={handleLoginSubmit} className="flex-1 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">Войти</button>
            </div>
          </div>
        </div>
      )}

      {/* User Header */}
      <div className="absolute top-4 right-4 sm:top-8 sm:right-8">
        {settings.username === 'Guest' ? (
          <button 
            onClick={() => setShowLoginModal(true)}
            className="flex items-center gap-2 text-indigo-600 hover:text-indigo-800 font-semibold bg-white px-4 py-2 rounded-full shadow-sm hover:shadow transition"
          >
            <LoginIcon /> Войти
          </button>
        ) : (
          <button 
            onClick={() => setView('profile')}
            className="flex items-center gap-2 text-indigo-900 hover:text-indigo-700 font-bold bg-white px-4 py-2 rounded-full shadow-sm hover:shadow transition"
          >
            <UserIcon /> Привет, {settings.username}
          </button>
        )}
      </div>

      <div className="text-center mb-12">
        <h1 className="text-6xl font-black tracking-tighter text-indigo-900 mb-2">
          ANN<span className="text-green-500">WORD</span>
        </h1>
        <p className="text-gray-500 text-lg">Тренируй мозг, учи слова</p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 w-full max-w-2xl">
        {/* Swapped Order: English First */}
        <button 
          onClick={() => { setSettings(s => ({ ...s, language: 'EN' })); setView('setup'); }}
          className="group relative bg-white hover:bg-blue-50 border-2 border-gray-100 hover:border-blue-200 rounded-2xl p-8 shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1"
        >
          <div className="text-4xl mb-3">🇬🇧</div>
          <h2 className="text-2xl font-bold text-gray-800 group-hover:text-blue-600">English</h2>
          <p className="text-gray-400 text-sm mt-2">Уровни A1-C1 или свой словарь</p>
        </button>

        <button 
          onClick={() => { setSettings(s => ({ ...s, language: 'RU' })); setView('setup'); }}
          className="group relative bg-white hover:bg-red-50 border-2 border-gray-100 hover:border-red-200 rounded-2xl p-8 shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1"
        >
          <div className="text-4xl mb-3">🇷🇺</div>
          <h2 className="text-2xl font-bold text-gray-800 group-hover:text-red-600">Русский</h2>
          <p className="text-gray-400 text-sm mt-2">Базовый словарь</p>
        </button>
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center p-6">
      <header className="w-full max-w-2xl flex items-center mb-8">
        <button onClick={() => setView('landing')} className="p-2 hover:bg-gray-200 rounded-full transition">
          <BackIcon />
        </button>
        <h2 className="text-2xl font-bold ml-4">Профиль игрока</h2>
      </header>

      <div className="bg-white rounded-2xl shadow-lg p-8 w-full max-w-2xl">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600">
            <UserIcon />
          </div>
          <div>
            <h3 className="text-2xl font-bold text-gray-900">{userProfile.username}</h3>
            <p className="text-gray-500">Статистика игр</p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-8">
          <div className="bg-gray-50 p-4 rounded-xl text-center">
            <div className="text-3xl font-black text-gray-900">{userProfile.stats.gamesPlayed}</div>
            <div className="text-sm text-gray-500 uppercase tracking-wide">Всего игр</div>
          </div>
          <div className="bg-green-50 p-4 rounded-xl text-center">
            <div className="text-3xl font-black text-green-600">{userProfile.stats.gamesWon}</div>
            <div className="text-sm text-green-600 uppercase tracking-wide">Побед</div>
          </div>
        </div>

        <h4 className="font-bold text-gray-800 mb-4">Лучшие слова</h4>
        <div className="flex flex-wrap gap-2">
          {Object.entries(userProfile.stats.wordsGuessed)
            .sort(([, a], [, b]) => b - a)
            .slice(0, 10)
            .map(([word, count]) => (
              <span key={word} className="px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full text-sm font-medium border border-indigo-100">
                {word} <span className="text-indigo-400 text-xs ml-1">x{count}</span>
              </span>
            ))}
          {Object.keys(userProfile.stats.wordsGuessed).length === 0 && (
            <p className="text-gray-400 italic">Пока нет угаданных слов</p>
          )}
        </div>
      </div>
    </div>
  );

  const renderSetup = () => (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4">
      <div className="bg-white rounded-3xl shadow-xl w-full max-w-md overflow-hidden">
        <div className="bg-indigo-600 p-6 text-white flex items-center relative">
          <button onClick={() => setView('landing')} className="absolute left-4 p-2 hover:bg-white/20 rounded-full transition">
            <BackIcon />
          </button>
          <h2 className="text-xl font-bold w-full text-center">
            Настройка игры ({settings.language})
          </h2>
        </div>

        <div className="p-6 space-y-8">

          {/* ENGLISH SPECIFIC: Source Selection */}
          {settings.language === 'EN' && (
            <div>
              <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Источник слов</label>
              <div className="flex bg-gray-100 p-1 rounded-xl">
                <button 
                  onClick={() => setSettings(s => ({ ...s, dictionarySource: 'builtin', useCustomDictionary: false }))}
                  className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition ${settings.dictionarySource === 'builtin' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  Школьный
                </button>
                <button 
                  onClick={() => setSettings(s => ({ ...s, dictionarySource: 'custom', useCustomDictionary: true }))}
                  className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition ${settings.dictionarySource === 'custom' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  Мой словарь
                </button>
              </div>
            </div>
          )}

          {/* ENGLISH BUILT-IN: Difficulty */}
          {settings.language === 'EN' && settings.dictionarySource === 'builtin' && (
            <div className="animate-fade-in">
              <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Сложность</label>
              <div className="grid grid-cols-4 gap-2">
                {(['A1', 'A2', 'B1', 'B2', 'C1', 'ALL'] as DifficultyLevel[]).map(level => (
                  <button
                    key={level}
                    onClick={() => setSettings(s => ({ ...s, difficulty: level }))}
                    className={`py-2 rounded-lg text-sm font-bold border-2 transition ${
                      settings.difficulty === level 
                        ? 'border-indigo-500 bg-indigo-50 text-indigo-700' 
                        : 'border-transparent bg-gray-100 text-gray-500 hover:bg-gray-200'
                    }`}
                  >
                    {level === 'ALL' ? 'Все' : level}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* ENGLISH CUSTOM: Upload */}
          {settings.language === 'EN' && settings.dictionarySource === 'custom' && (
            <div className="animate-fade-in bg-yellow-50 border border-yellow-100 rounded-xl p-4">
              <label className="block text-sm font-bold text-yellow-800 mb-2">Загрузить файл (.txt)</label>
              {isUploadingDict ? (
                 <div className="flex items-center gap-2 text-sm text-yellow-700 animate-pulse py-2">
                   <LoaderIcon /> Загрузка...
                 </div>
              ) : (
                <input 
                  type="file" 
                  accept=".txt" 
                  onChange={handleFileUpload}
                  className="block w-full text-xs text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-yellow-200 file:text-yellow-800 hover:file:bg-yellow-300 cursor-pointer"
                />
              )}
              <p className="text-xs text-yellow-600/70 mt-2">
                Текущий словарь: {userProfile.customDictionaryEn.length > 0 ? `${userProfile.customDictionaryEn.length} слов` : 'Пусто'}
              </p>
            </div>
          )}

          {/* COMMON: Word Length */}
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Длина слова</label>
            <div className="flex gap-4">
              {[4, 5, 6].map(len => (
                <button
                  key={len}
                  onClick={() => setSettings(s => ({...s, wordLength: len as WordLength}))}
                  className={`flex-1 py-4 rounded-xl font-black text-xl border-2 transition transform active:scale-95 ${
                    settings.wordLength === len 
                      ? 'border-indigo-600 bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
                      : 'border-gray-200 bg-white text-gray-400 hover:border-gray-300'
                  }`}
                >
                  {len}
                </button>
              ))}
            </div>
          </div>

          <button 
            onClick={startNewGame}
            disabled={settings.language === 'EN' && settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length === 0}
            className="w-full bg-green-500 hover:bg-green-600 disabled:bg-gray-300 text-white font-bold py-4 rounded-xl text-lg shadow-xl shadow-green-100 transition transform active:scale-[0.98] mt-8"
          >
            Играть
          </button>
        </div>
      </div>
    </div>
  );

  // --- Main Switch ---

  if (view === 'landing') return renderLanding();
  if (view === 'profile') return renderProfile();
  if (view === 'setup') return renderSetup();

  // --- Game View ---
  return (
    <div className="flex flex-col h-screen items-center bg-gray-50 overflow-hidden relative">
      <header className="w-full border-b bg-white p-4 flex justify-between items-center shadow-sm z-10 shrink-0">
        <button onClick={() => setView('landing')} className="p-2 hover:bg-gray-100 rounded-full text-gray-600 hover:text-indigo-600 transition" title="Домой">
          <HomeIcon />
        </button>
        <h1 className="text-2xl font-bold tracking-wider">
          ANN<span className="text-green-600">WORD</span>
        </h1>
        <div className="w-10"></div>
      </header>

      {/* Error Toast */}
      <div className={`absolute top-20 z-50 transition-all duration-300 ${gameState.error ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}`}>
        <div className="bg-black text-white px-4 py-2 rounded-md font-bold shadow-lg">
          {gameState.error}
        </div>
      </div>

      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-lg p-2 overflow-hidden h-full">

        {/* --- English specific: Translation History Ticker & Hints --- */}
        {settings.language === 'EN' && gameState.gameStatus === 'playing' && (
           <div className="w-full mb-1 shrink-0 flex flex-col items-center justify-end gap-1">

             {/* History Ticker - COMPACT FOR MOBILE */}
             {gameState.history.length > 0 && (
               <div 
                 ref={historyScrollRef}
                 className="w-full overflow-x-auto whitespace-nowrap scrollbar-hide py-1 px-2 flex gap-2"
               >
                 {gameState.history.map((item, idx) => (
                   <div key={idx} className="inline-flex items-center bg-white border border-indigo-100 rounded-lg shadow-sm px-2 py-1 animate-bounce-in">
                     <span className="font-bold text-gray-800 text-xs">{item.word}</span>
                     {item.translation && (
                       <>
                         <span className="mx-1 text-gray-300 text-xs">|</span>
                         <span className="text-indigo-600 text-xs max-w-[80px] truncate">{item.translation}</span>
                       </>
                     )}
                   </div>
                 ))}
               </div>
             )}

             {/* Hint Button - COMPACT */}
             {!gameState.hint && !gameState.loadingHint ? (
               <button 
                onClick={fetchHint}
                className="text-xs bg-indigo-50 border border-indigo-100 text-indigo-700 px-3 py-1.5 rounded-full font-semibold hover:bg-indigo-100 transition shadow-sm"
               >
                 💡 Подсказка
               </button>
             ) : gameState.loadingHint ? (
               <div className="bg-indigo-50 border border-indigo-100 text-indigo-500 px-3 py-1.5 rounded-full text-xs font-semibold flex items-center gap-2">
                 <LoaderIcon /> Думаю...
               </div>
             ) : (
               <div className="bg-indigo-50 border border-indigo-200 text-indigo-800 p-2 rounded-lg text-xs text-center shadow-sm animate-fade-in w-full max-h-16 overflow-y-auto">
                 <span className="font-bold">Подсказка:</span> {gameState.hint}
               </div>
             )}
           </div>
        )}

        {/* Grid Container */}
        <div className="flex-grow flex items-center justify-center w-full max-h-[65vh]">
          <Grid 
            guesses={gameState.guesses}
            currentGuess={gameState.currentGuess}
            secretWord={gameState.secretWord}
            wordLength={settings.wordLength}
            maxGuesses={MAX_GUESSES}
            shakeRowIndex={shakeRowIndex}
          />
        </div>

        {gameState.gameStatus !== 'playing' && (
          <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-40 p-4 bg-white/95 backdrop-blur rounded-lg shadow-2xl border text-center animate-bounce-in w-11/12 max-w-sm">
             <h2 className="text-xl font-bold mb-2">
               {gameState.gameStatus === 'won' ? '🎉 Победа!' : '😔 Вы проиграли'}
             </h2>
             <p className="mb-2 text-gray-700">
               Загаданное слово: <span className="font-bold text-black text-lg">{gameState.secretWord}</span>
             </p>
             {/* Show Translation and Level if available */}
             {gameState.secretWordData && (
                <div className="mb-4 text-sm">
                  <span className="block text-gray-500">Перевод: <span className="text-indigo-600 font-semibold">{gameState.secretWordData.translation}</span></span>
                  <span className="block text-gray-500 text-xs mt-1">Уровень: <span className="bg-gray-200 px-1.5 py-0.5 rounded text-gray-700 font-bold">{gameState.secretWordData.level}</span></span>
                </div>
             )}
             <div className="flex gap-2 justify-center">
                <button 
                  onClick={() => setView('landing')}
                  className="bg-gray-100 text-gray-700 px-4 py-3 rounded-lg font-bold hover:bg-gray-200 transition"
                >
                  Меню
                </button>
                <button 
                  onClick={startNewGame}
                  className="bg-green-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-green-700 flex items-center justify-center gap-2 transition shadow-md"
                >
                  <RefreshIcon /> Играть снова
                </button>
             </div>
          </div>
        )}
      </main>

      <footer className="w-full bg-gray-100 pb-4 pt-2 border-t flex justify-center shrink-0">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>
    </div>
  );
};

