                <button 
                  onClick={() => {
                    // Check if user is logged in before allowing custom dict
                    if (settings.username === 'Guest') {
                        setAuthError("Для доступа к своему словарю необходимо войти в аккаунт");
                        setAuthMode('login');
                        setShowLoginModal(true);
                    } else {
                        setSettings(s => ({ ...s, dictionarySource: 'custom', useCustomDictionary: true }));
                    }
                  }}
                  className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition flex items-center justify-center gap-1 ${
                    settings.dictionarySource === 'custom' 
                      ? 'bg-white text-indigo-600 shadow-sm' 
                      : 'text-gray-500 hover:text-gray-700'
                  }`}
                >
                  {settings.username === 'Guest' && <LockIcon />}
                  Мой словарь
                </button>
              </div>
            </div>
          )}

          {/* ENGLISH BUILT-IN: Difficulty */}
          {settings.language === 'EN' && settings.dictionarySource === 'builtin' && (
            <div className="animate-fade-in">
              <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Сложность</label>
              <div className="grid grid-cols-4 gap-2">
                {(['A1', 'A2', 'B1', 'B2', 'C1', 'C2', 'ALL'] as DifficultyLevel[]).map(level => (
                  <button
                    key={level}
                    onClick={() => setSettings(s => ({ ...s, difficulty: level }))}
                    className={`py-2 rounded-lg text-sm font-bold border-2 transition ${
                      settings.difficulty === level 
                        ? 'border-indigo-500 bg-indigo-50 text-indigo-700' 
                        : 'border-transparent bg-gray-100 text-gray-500 hover:bg-gray-200'
                    }`}
                  >
                    {level === 'ALL' ? 'Все' : level}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* ENGLISH CUSTOM: Upload */}
          {settings.language === 'EN' && settings.dictionarySource === 'custom' && (
            <div className="animate-fade-in bg-yellow-50 border border-yellow-100 rounded-xl p-4">
              <label className="block text-sm font-bold text-yellow-800 mb-2">Загрузить файл (.txt)</label>
              {isUploadingDict ? (
                 <div className="flex items-center gap-2 text-sm text-yellow-700 animate-pulse py-2">
                   <LoaderIcon /> Загрузка...
                 </div>
              ) : (
                <input 
                  type="file" 
                  accept=".txt" 
                  onChange={handleFileUpload}
                  className="block w-full text-xs text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-yellow-200 file:text-yellow-800 hover:file:bg-yellow-300 cursor-pointer"
                />
              )}
              <p className="text-xs text-yellow-600/70 mt-2">
                Текущий словарь: {userProfile.customDictionaryEn.length > 0 ? `${userProfile.customDictionaryEn.length} слов` : 'Пусто'}
              </p>
            </div>
          )}

          {/* COMMON: Word Length */}
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-3 tracking-wider">Длина слова</label>
            <div className="flex gap-4">
              {[4, 5, 6].map(len => (
                <button
                  key={len}
                  onClick={() => setSettings(s => ({...s, wordLength: len as WordLength}))}
                  className={`flex-1 py-4 rounded-xl font-black text-xl border-2 transition transform active:scale-95 ${
                    settings.wordLength === len 
                      ? 'border-indigo-600 bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
                      : 'border-gray-200 bg-white text-gray-400 hover:border-gray-300'
                  }`}
                >
                  {len}
                </button>
              ))}
            </div>
          </div>

          <button 
            onClick={startNewGame}
            disabled={settings.language === 'EN' && settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length === 0}
            className="w-full bg-green-500 hover:bg-green-600 disabled:bg-gray-300 text-white font-bold py-4 rounded-xl text-lg shadow-xl shadow-green-100 transition transform active:scale-[0.98] mt-8"
          >
            Играть
          </button>
        </div>
      </div>
    </div>
  );

  const renderGame = () => (
    <div className="flex flex-col h-screen items-center bg-gray-50 overflow-hidden relative">
      <header className="w-full border-b bg-white p-4 flex justify-between items-center shadow-sm z-10 shrink-0">
        <button onClick={() => setView('landing')} className="p-2 hover:bg-gray-100 rounded-full text-gray-600 hover:text-indigo-600 transition" title="Домой">
          <HomeIcon />
        </button>
        <h1 className="text-2xl font-bold tracking-wider">
          ANN<span className="text-green-600">WORD</span>
        </h1>
        <div className="w-10"></div>
      </header>

      {/* Error Toast */}
      <div className={`absolute top-20 z-50 transition-all duration-300 ${gameState.error ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}`}>
        <div className="bg-black text-white px-4 py-2 rounded-md font-bold shadow-lg">
          {gameState.error}
        </div>
      </div>

      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-lg p-2 overflow-hidden h-full">

        {/* --- English specific: Translation History Ticker & Hints --- */}
        {settings.language === 'EN' && gameState.gameStatus === 'playing' && (
           <div className="w-full mb-1 shrink-0 flex flex-col items-center justify-end gap-1">

             {/* History Ticker - COMPACT FOR MOBILE */}
             {gameState.history.length > 0 && (
               <div 
                 ref={historyScrollRef}
                 className="w-full overflow-x-auto whitespace-nowrap no-scrollbar py-1 px-2 flex gap-2"
               >
                 {gameState.history.map((item, idx) => (
                   <div key={idx} className="inline-flex items-center bg-white border border-indigo-100 rounded-lg shadow-sm px-2 py-1 animate-bounce-in">
                     <span className="font-bold text-gray-800 text-xs">{item.word}</span>
                     {item.translation && (
                       <>
                         <span className="mx-1 text-gray-300 text-xs">|</span>
                         <span className="text-indigo-600 text-xs max-w-[80px] truncate">{item.translation}</span>
                       </>
                     )}
                   </div>
                 ))}
               </div>
             )}

             {/* Hint Button - COMPACT */}
             {!gameState.hint && !gameState.loadingHint ? (
               <button 
                onClick={fetchHint}
                className="text-xs bg-indigo-50 border border-indigo-100 text-indigo-700 px-3 py-1.5 rounded-full font-semibold hover:bg-indigo-100 transition shadow-sm"
               >
                 💡 Подсказка
               </button>
             ) : gameState.loadingHint ? (
               <div className="bg-indigo-50 border border-indigo-100 text-indigo-500 px-3 py-1.5 rounded-full text-xs font-semibold flex items-center gap-2">
                 <LoaderIcon /> Думаю...
               </div>
             ) : (
               <div className="bg-indigo-50 border border-indigo-200 text-indigo-800 p-2 rounded-lg text-xs text-center shadow-sm animate-fade-in w-full max-h-16 overflow-y-auto">
                 <span className="font-bold">Подсказка:</span> {gameState.hint}
               </div>
             )}
           </div>
        )}

        {/* Grid Container */}
        <div className="flex-grow flex items-center justify-center w-full max-h-[65vh]">
          <Grid 
            guesses={gameState.guesses}
            currentGuess={gameState.currentGuess}
            secretWord={gameState.secretWord}
            wordLength={settings.wordLength}
            maxGuesses={MAX_GUESSES}
            shakeRowIndex={shakeRowIndex}
          />
        </div>

        {gameState.gameStatus !== 'playing' && (
          <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-40 p-4 bg-white/95 backdrop-blur rounded-lg shadow-2xl border text-center animate-bounce-in w-11/12 max-w-sm">
             <h2 className="text-xl font-bold mb-2">
               {gameState.gameStatus === 'won' ? '🎉 Победа!' : '😔 Вы проиграли'}
             </h2>
             <p className="mb-2 text-gray-700">
               Загаданное слово: <span className="font-bold text-black text-lg">{gameState.secretWord}</span>
             </p>
             {/* Show Translation and Level if available */}
             {gameState.secretWordData && (
                <div className="mb-4 text-sm">
                  <span className="block text-gray-500">Перевод: <span className="text-indigo-600 font-semibold">{gameState.secretWordData.translation}</span></span>
                  <span className="block text-gray-500 text-xs mt-1">Уровень: <span className="bg-gray-200 px-1.5 py-0.5 rounded text-gray-700 font-bold">{gameState.secretWordData.level}</span></span>
                </div>
             )}
             <div className="flex gap-2 justify-center">
                <button 
                  onClick={() => setView('landing')}
                  className="bg-gray-100 text-gray-700 px-4 py-3 rounded-lg font-bold hover:bg-gray-200 transition"
                >
                  Меню
                </button>
                <button 
                  onClick={startNewGame}
                  className="bg-green-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-green-700 flex items-center justify-center gap-2 transition shadow-md"
                >
                  <RefreshIcon /> Играть снова
                </button>
             </div>
          </div>
        )}
      </main>

      <footer className="w-full bg-gray-100 pb-4 pt-2 border-t flex justify-center shrink-0">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>
    </div>
  );

  // --- Main Switch ---
  let content;
  if (view === 'landing') content = renderLanding();
  else if (view === 'profile') content = renderProfile();
  else if (view === 'setup') content = renderSetup();
  else content = renderGame();

  return (
    <>
      {renderAuthModal()}
      {renderRulesModal()}
      {content}
    </>
  );
};

export default App;

