/**
 * Calculates the Levenshtein distance between two strings.
 * Used to determine if a user made a typo (distance 1 or 2).
 */
export const levenshteinDistance = (a: string, b: string): number => {
  const matrix = [];

  for (let i = 0; i <= b.length; i++) {
    matrix[i] = [i];
  }

  for (let j = 0; j <= a.length; j++) {
    matrix[0][j] = j;
  }

  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1, // substitution
          Math.min(
            matrix[i][j - 1] + 1, // insertion
            matrix[i - 1][j] + 1 // deletion
          )
        );
      }
    }
  }

  return matrix[b.length][a.length];
};

/**
 * Finds the closest word in the dictionary to the input word.
 * Only considers words with the same length (or +/- 1 if desired, but Wordle is strict on length).
 * We assume Wordle input implies intended length is strict, but for typo detection 
 * in a general sense, we allow distance calculation.
 * 
 * Returns the closest word if distance <= threshold, else null.
 */
export const findClosestWord = (input: string, dictionary: string[], threshold: number = 1): string | null => {
  let closestWord = null;
  let minDistance = Infinity;

  // Optimization: Only check words of similar length to avoid expensive calcs on disparate words
  const len = input.length;

  for (const word of dictionary) {
    if (Math.abs(word.length - len) > 2) continue;

    const dist = levenshteinDistance(input, word);

    if (dist < minDistance) {
      minDistance = dist;
      closestWord = word;
    }

    // Exact match or very close, return early if possible (though exact match shouldn't happen here usually)
    if (dist === 0) return word;
  }

  return minDistance <= threshold ? closestWord : null;
};

/**
 * Scrambles a word for the mini-game.
 */
export const scrambleWord = (word: string): string => {
  const arr = word.split('');
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  // Ensure it's not same as original if possible
  const result = arr.join('');
  if (result === word && word.length > 1) return scrambleWord(word);
  return result;
};

/**
 * Replaces random letters with underscores for "Gap Fill" game.
 */
export const createGapWord = (word: string): { display: string, missingIndices: number[] } => {
  const chars = word.split('');
  const missingIndices: number[] = [];

  // Mask approx 30-50% of letters
  const numToMask = Math.max(1, Math.floor(word.length * 0.4));

  while (missingIndices.length < numToMask) {
    const idx = Math.floor(Math.random() * word.length);
    if (!missingIndices.includes(idx)) {
      missingIndices.push(idx);
    }
  }

  const display = chars.map((char, i) => missingIndices.includes(i) ? '_' : char).join(' ');
  return { display, missingIndices };
};

import { UserProfile, UserStats, JailedWord, PetState } from "../types";

// --- MOCK DATABASE IMPLEMENTATION ---
// В реальном приложении здесь были бы запросы fetch() к API бэкенда.
// Мы имитируем базу данных пользователей, хранящуюся в LocalStorage под одним ключом.

const DB_KEY = 'annword_users_db_v2'; // Changed key version to reset/migrate structure if needed
const SIMULATED_NETWORK_DELAY = 600; // ms

interface UserRecord extends UserProfile {
  password: string; // В реальном БД здесь был бы хеш пароля
}

// Helpers
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

const getDB = (): Record<string, UserRecord> => {
  try {
    const data = localStorage.getItem(DB_KEY);
    return data ? JSON.parse(data) : {};
  } catch {
    return {};
  }
};

const saveDB = (db: Record<string, UserRecord>) => {
  localStorage.setItem(DB_KEY, JSON.stringify(db));
};

export const userService = {
  /**
   * Авторизация пользователя по логину и паролю.
   */
  login: async (username: string, password: string): Promise<UserProfile> => {
    await delay(SIMULATED_NETWORK_DELAY);
    const db = getDB();
    const key = username.trim().toLowerCase();
    const user = db[key];

    if (!user) {
      throw new Error("Пользователь не найден. Пожалуйста, зарегистрируйтесь.");
    }

    if (user.password !== password) {
      throw new Error("Неверный пароль.");
    }

    // Возвращаем профиль без поля пароля
    const { password: _, ...profile } = user;

    // Initialize new fields if they don't exist (migration for older users)
    if (!profile.wordJail) profile.wordJail = [];
    if (!profile.pet) profile.pet = { name: 'Owl', level: 1, mood: 'neutral', xp: 0 };

    return profile;
  },

  /**
   * Регистрация нового пользователя.
   */
  register: async (username: string, password: string): Promise<UserProfile> => {
    await delay(SIMULATED_NETWORK_DELAY);
    const db = getDB();
    const key = username.trim().toLowerCase();

    if (db[key]) {
      throw new Error("Пользователь с таким именем уже существует.");
    }

    const newUser: UserRecord = {
      username: username.trim(),
      password,
      customDictionaryEn: [],
      stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} },
      wordJail: [],
      pet: { name: 'Owl', level: 1, mood: 'happy', xp: 0 }
    };

    db[key] = newUser;
    saveDB(db);

    const { password: _, ...profile } = newUser;
    return profile;
  },

  /**
   * Получение профиля.
   */
  getUserProfile: async (username: string): Promise<UserProfile> => {
    await delay(400);
    const db = getDB();
    const key = username.trim().toLowerCase();
    const user = db[key];
    if (!user) throw new Error("User not found");
    const { password: _, ...profile } = user;
    return profile;
  },

  /**
   * Обновление статистики.
   */
  updateUserStats: async (username: string, newStats: UserStats): Promise<void> => {
    await delay(400);
    const db = getDB();
    const key = username.trim().toLowerCase();
    if (db[key]) {
      db[key].stats = newStats;
      saveDB(db);
    }
  },

  /**
   * Обновление словаря пользователя.
   */
  updateUserDictionary: async (username: string, dictionary: string[]): Promise<void> => {
    await delay(500);
    const db = getDB();
    const key = username.trim().toLowerCase();
    if (db[key]) {
      db[key].customDictionaryEn = dictionary;
      saveDB(db);
    }
  },

  /**
   * Add a word to the "Jail" because of a mistake/typo.
   */
  addWordToJail: async (username: string, word: string, translation: string = ''): Promise<JailedWord> => {
    const db = getDB();
    const key = username.trim().toLowerCase();

    if (!db[key]) throw new Error("User not found");

    const jail = db[key].wordJail || [];
    const existingIndex = jail.findIndex(w => w.word === word);

    let updatedWord: JailedWord;

    if (existingIndex >= 0) {
      // Already in jail, increase mistake count and lock it tighter
      const w = jail[existingIndex];
      w.mistakesCount += 1;
      // If it was free, lock it again but with less severity than a new word
      if (w.isFree) {
        w.isFree = false;
        w.correctionLevel = 1; // Start at 1/3
      }
      updatedWord = w;
      jail[existingIndex] = w;
    } else {
      // New prisoner
      updatedWord = {
        word,
        translation,
        mistakesCount: 1,
        correctionLevel: 0,
        isFree: false
      };
      jail.push(updatedWord);
    }

    // Update Pet Mood to SAD because of mistake
    if (!db[key].pet) db[key].pet = { name: 'Owl', level: 1, mood: 'neutral', xp: 0 };
    db[key].pet.mood = 'sad';

    db[key].wordJail = jail;
    saveDB(db);
    return updatedWord;
  },

  /**
   * Progress a word in jail (mini-game success).
   */
  progressWordInJail: async (username: string, word: string): Promise<{ word: JailedWord, pet: PetState }> => {
    const db = getDB();
    const key = username.trim().toLowerCase();
    if (!db[key]) throw new Error("User not found");

    const jail = db[key].wordJail || [];
    const wordIndex = jail.findIndex(w => w.word === word);

    if (wordIndex === -1) throw new Error("Word not in jail");

    const w = jail[wordIndex];
    w.correctionLevel += 1;

    // Check if freed
    if (w.correctionLevel >= 3) {
      w.isFree = true;
      w.correctionLevel = 3;

      // Feed Pet
      db[key].pet.xp += 10;
      db[key].pet.mood = 'happy';

      // Level up pet?
      if (db[key].pet.xp >= db[key].pet.level * 50) {
        db[key].pet.level += 1;
        db[key].pet.mood = 'excited';
      }
    }

    db[key].wordJail = jail;
    saveDB(db);

    return { word: w, pet: db[key].pet };
  }
};

