    setActiveWord(null);
    setGameType('none');
    setUserInput('');
    setFeedback('none');
  };

  const startMiniGame = (wordItem: JailedWord) => {
    setActiveWord(wordItem);
    setFeedback('none');
    setUserInput('');

    // Randomly choose game type
    const type: MiniGameType = Math.random() > 0.5 ? 'gap' : 'scramble';
    setGameType(type);

    if (type === 'scramble') {
      setScrambled(scrambleWord(wordItem.word));
    } else {
      setGapData(createGapWord(wordItem.word));
    }
  };

  const checkAnswer = async () => {
    if (!activeWord) return;

    let isCorrect = false;
    const target = activeWord.word.toUpperCase();
    const attempt = userInput.toUpperCase().trim();

    if (gameType === 'scramble') {
      isCorrect = attempt === target;
    } else {
      // Gap fill logic requires rebuilding the word based on input char or full word logic?
      // Simple version: user types the FULL word to confirm they know it
      isCorrect = attempt === target;
    }

    if (isCorrect) {
      setFeedback('success');
      // Update logic in backend
      await onFreeAttempt(activeWord.word);
      setTimeout(() => resetGame(), 1500); // Close mini-game after success
    } else {
      setFeedback('fail');
      setTimeout(() => setFeedback('none'), 1000);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-fade-in">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg h-[80vh] flex flex-col relative overflow-hidden">

        {/* Header */}
        <div className="bg-slate-800 p-4 text-white flex justify-between items-center shrink-0">
          <div className="flex items-center gap-3">
            <span className="text-3xl">🏰</span>
            <div>
              <h2 className="text-xl font-bold">Тюрьма слов</h2>
              <p className="text-xs text-slate-400">Освободи слова, чтобы покормить Питомца</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full text-xl">✕</button>
        </div>

        {/* Content Area */}
        <div className="flex-grow overflow-y-auto p-4 bg-slate-50">

          {/* Active Mini Game */}
          {activeWord ? (
            <div className="bg-white p-6 rounded-2xl shadow-lg border-2 border-indigo-100 flex flex-col items-center gap-6 animate-bounce-in">
              <h3 className="text-lg font-bold text-gray-500 uppercase tracking-widest">
                {gameType === 'scramble' ? 'Собери слово' : 'Впиши слово целиком'}
              </h3>

              <div className="text-4xl font-black text-indigo-600 tracking-widest text-center">
                {gameType === 'scramble' ? scrambled : gapData?.display}
              </div>

              {activeWord.translation && (
                <p className="text-sm text-gray-400">{activeWord.translation}</p>
              )}

              <input 
                autoFocus
                type="text" 
                value={userInput}
                onChange={(e) => setUserInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && checkAnswer()}
                className={`w-full text-center text-2xl font-bold p-3 border-b-4 outline-none transition-colors ${
                  feedback === 'fail' ? 'border-red-500 bg-red-50' : 
                  feedback === 'success' ? 'border-green-500 bg-green-50' : 'border-indigo-200 focus:border-indigo-500'
                }`}
                placeholder="Введи слово..."
              />

              <div className="flex gap-2 w-full">
                <button 
                  onClick={resetGame}
                  className="flex-1 py-3 text-gray-500 font-bold hover:bg-gray-100 rounded-xl"
                >
                  Отмена
                </button>
                <button 
                  onClick={checkAnswer}
                  className="flex-1 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg"
                >
                  Проверить
                </button>
              </div>
            </div>
          ) : (
            /* List of Prisoners */
            <div className="space-y-6">

              {/* Prisoners Section */}
              <div>
                <h3 className="text-sm font-bold text-slate-500 uppercase mb-3 flex items-center gap-2">
                  Заключенные ({prisoners.length})
                  {prisoners.length === 0 && <span className="text-green-500 text-xs">Пусто! Отличная работа!</span>}
                </h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {prisoners.map((w) => (
                    <button 
                      key={w.word}
                      onClick={() => startMiniGame(w)}
                      className="bg-white border-2 border-slate-200 p-3 rounded-xl flex items-center justify-between hover:border-indigo-400 hover:shadow-md transition group text-left"
                    >
                      <div>
                        <div className="font-bold text-slate-700 group-hover:text-indigo-600">{w.word}</div>
                        {w.translation && <div className="text-xs text-slate-400">{w.translation}</div>}
                      </div>

                      {/* Jail Bars Visualization */}
                      <div className="flex gap-1">
                        {[1, 2, 3].map(step => (
                          <div key={step} className={`w-2 h-6 rounded-full ${step <= w.correctionLevel ? 'bg-green-400' : 'bg-slate-200'}`}></div>
                        ))}
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Freed Section */}
              {freed.length > 0 && (
                <div className="opacity-60 grayscale hover:grayscale-0 transition duration-500">
                  <h3 className="text-sm font-bold text-slate-400 uppercase mb-3">Освобожденные ({freed.length})</h3>
                  <div className="flex flex-wrap gap-2">
                    {freed.map(w => (
                      <span key={w.word} className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-bold border border-green-200">
                        {w.word}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

