const App: React.FC = () => {
  // --- State ---
  const [view, setView] = useState<ViewState>('landing');
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [showRulesModal, setShowRulesModal] = useState(false);
  const [showJailModal, setShowJailModal] = useState(false); // NEW: Jail Modal state
  const [setupError, setSetupError] = useState<string | null>(null);

  // Auth Form State
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [tempUsername, setTempUsername] = useState('');
  const [tempPassword, setTempPassword] = useState('');
  const [authError, setAuthError] = useState<string | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(false);

  const [settings, setSettings] = useState<GameSettings>({
    language: 'EN',
    wordLength: 5,
    useCustomDictionary: false,
    dictionarySource: 'builtin',
    difficulty: 'ALL',
    username: 'Guest',
  });

  // Profile Data
  const [userProfile, setUserProfile] = useState<UserProfile>({
    username: 'Guest',
    customDictionaryEn: [],
    stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} },
    wordJail: [],
    pet: { name: 'Owl', level: 1, mood: 'neutral', xp: 0 }
  });

  // Loading States
  const [isUploadingDict, setIsUploadingDict] = useState(false);
  const [shakeRowIndex, setShakeRowIndex] = useState<number | null>(null);

  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    secretWordData: null,
    guesses: [],
    history: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });

  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  const historyScrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll history
  useEffect(() => {
    if (historyScrollRef.current) {
      historyScrollRef.current.scrollLeft = historyScrollRef.current.scrollWidth;
    }
  }, [gameState.history]);

  // Clear setup error when settings change
  useEffect(() => {
    setSetupError(null);
  }, [settings]);

  // --- Auth & Profile Management ---

  const handleAuthSubmit = async () => {
    if (!tempUsername.trim() || !tempPassword.trim()) {
      setAuthError("Заполните все поля");
      return;
    }

    setIsAuthLoading(true);
    setAuthError(null);

    try {
      let profile: UserProfile;
      if (authMode === 'login') {
        profile = await userService.login(tempUsername, tempPassword);
      } else {
        profile = await userService.register(tempUsername, tempPassword);
      }

      setUserProfile(profile);
      setSettings(prev => ({ ...prev, username: profile.username }));
      setShowLoginModal(false);
      // Reset form
      setTempUsername('');
      setTempPassword('');
    } catch (err: any) {
      setAuthError(err.message || "Ошибка авторизации");
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleLogout = () => {
    setSettings(prev => ({ 
      ...prev, 
      username: 'Guest',
      dictionarySource: 'builtin', // Reset to builtin on logout
      useCustomDictionary: false
    }));
    setUserProfile({
      username: 'Guest',
      customDictionaryEn: [],
      stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} },
      wordJail: [],
      pet: { name: 'Owl', level: 1, mood: 'neutral', xp: 0 }
    });
    setView('landing');
  };


  // --- Game Helpers ---

  // 1. POOL FOR SECRET WORD
  const getSecretWordPool = useCallback(() => {
    if (settings.language === 'EN') {
       if (settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length > 0) {
          // Custom dictionary are plain strings.
          return userProfile.customDictionaryEn.map(w => ({ word: w, translation: '', level: 'Custom' }));
       } else if (settings.dictionarySource === 'anya') {
          // Anya's Dictionary
          return ANYAS_DICTIONARY.map(w => ({ word: w, translation: '', level: 'Anya' }));
       }

       // Built-in Dictionary with Difficulty Filter
       let pool = COMMON_WORDS_EN;
       if (settings.difficulty !== 'ALL') {
         pool = pool.filter(w => w.level === settings.difficulty);
       }
       return pool;
    } else {
       // Russian dictionary
       return COMMON_WORDS_RU;
    }
  }, [settings.language, settings.dictionarySource, settings.difficulty, userProfile.customDictionaryEn]);

  // 2. POOL FOR VALIDATION
  const getValidationPool = useCallback(() => {
    const basePool = settings.language === 'EN' ? ALL_WORDS_EN : ALL_WORDS_RU;
    let combinedPool = basePool.filter(w => w.length === settings.wordLength).map(w => w.toUpperCase());

    // Add Custom Dictionary words
    if (settings.language === 'EN' && userProfile.customDictionaryEn.length > 0) {
       const customFiltered = userProfile.customDictionaryEn
         .filter(w => w.length === settings.wordLength)
         .map(w => w.toUpperCase());
       combinedPool = [...combinedPool, ...customFiltered];
    }

    // Add Anya's Dictionary words
    if (settings.language === 'EN') {
        const anyasFiltered = ANYAS_DICTIONARY
          .filter(w => w.length === settings.wordLength)
          .map(w => w.toUpperCase());
        combinedPool = [...combinedPool, ...anyasFiltered];
    }

    // Deduplicate
    return Array.from(new Set(combinedPool));
  }, [settings.language, settings.wordLength, userProfile.customDictionaryEn]);


  const startNewGame = useCallback(() => {
    setSetupError(null);
    const rawPool = getSecretWordPool();

    // Filter by length
    // rawPool is always EnrichedWord[] because getSecretWordPool normalizes all inputs.
    const filteredPool = rawPool.filter(w => w.word.length === settings.wordLength);

    if (filteredPool.length === 0) {
      let msg = "Слов с такими настройками не найдено.";
      if (settings.language === 'EN' && settings.dictionarySource === 'custom') {
        msg = `В вашем словаре нет слов длиной ${settings.wordLength}.`;
      } else if (settings.language === 'EN' && settings.dictionarySource === 'anya') {
        msg = `В словаре Ани нет слов длиной ${settings.wordLength}.`;
      } else if (settings.language === 'EN') {
        msg = `В словаре нет слов уровня ${settings.difficulty} длиной ${settings.wordLength}.`;
      }
      setSetupError(msg);
      return; // Stop here, do not change view to game
    }

    // If we have words, pick one
    let secretWord = '';
    let secretWordData: EnrichedWord | null = null;

    if (filteredPool.length > 0) {
      // Prioritize Words from Jail? (Mechanic 1 from suggestions)
      // For now, simple random
      const randomEntry = filteredPool[Math.floor(Math.random() * filteredPool.length)];
      secretWord = randomEntry.word;
      secretWordData = randomEntry;
    }

    setGameState({
      secretWord: secretWord,
      secretWordData: secretWordData,
      guesses: [],
      history: [],
      currentGuess: '',
      gameStatus: 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: null,
    });
    setKeyStatuses({});
    setView('game');
  }, [getSecretWordPool, settings.wordLength, settings.language, settings.dictionarySource, settings.difficulty]);


  // --- Logic ---

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char, error: null }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1), error: null }));
  };

  const updateStats = async (won: boolean, word: string) => {
    if (userProfile.username === 'Guest') return; // Guest stats are not persisted

    const newStats = { ...userProfile.stats };
    newStats.gamesPlayed += 1;
    if (won) {
      newStats.gamesWon += 1;
      newStats.wordsGuessed[word] = (newStats.wordsGuessed[word] || 0) + 1;
    }

    // Save locally immediately
    setUserProfile(prev => ({ ...prev, stats: newStats }));

    try {
      await userService.updateUserStats(userProfile.username, newStats);
    } catch (e) {
      console.error("Failed to sync stats to server", e);
    }
  };

  // --- NEW: Jail Logic ---
  const handleJailAttempt = async (word: string): Promise<boolean> => {
    if (userProfile.username === 'Guest') return false;
    try {
      const res = await userService.progressWordInJail(userProfile.username, word);
      setUserProfile(prev => ({ ...prev, wordJail: prev.wordJail.map(w => w.word === word ? res.word : w), pet: res.pet }));
      return true;
    } catch (e) {
      console.error(e);
      return false;
    }
  };

  const triggerShake = () => {
    setShakeRowIndex(gameState.rowIndex);
    setTimeout(() => setShakeRowIndex(null), 600);
  };

  const handleEnter = async () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) {
       setGameState(prev => ({ ...prev, error: "Недостаточно букв" }));
       triggerShake();
       return;
    }

    const validWords = getValidationPool();
    if (!validWords.includes(gameState.currentGuess)) {
      // --- NEW: MISTAKE TRAPPING ---
      // User entered an invalid word. Check for typos.
      const typoCorrection = findClosestWord(gameState.currentGuess, validWords, 1);

      if (typoCorrection && userProfile.username !== 'Guest') {
         // Found a likely intended word. Send it to Jail!
         // Get translation if available
         const wordEntry = COMMON_WORDS_EN.find(w => w.word === typoCorrection);
         const translation = wordEntry ? wordEntry.translation : '';

         // Update UI toast
         setGameState(prev => ({ ...prev, error: `Вы имели в виду ${typoCorrection}? Сохранено в Тюрьму!` }));

         // Async update
         try {
           const jailed = await userService.addWordToJail(userProfile.username, typoCorrection, translation);
           setUserProfile(prev => {
             // Replace if exists or push
             const existingIdx = prev.wordJail.findIndex(w => w.word === typoCorrection);
             const newJail = [...prev.wordJail];
             if (existingIdx >= 0) newJail[existingIdx] = jailed;
             else newJail.push(jailed);

             return { ...prev, wordJail: newJail, pet: { ...prev.pet, mood: 'sad' } }; // Pet gets sad on mistakes
           });
         } catch (e) { console.error(e); }

      } else {
         setGameState(prev => ({ ...prev, error: "Такого слова нет в словаре" }));
      }

      triggerShake();
      return;
    }

    // --- EXISTING GAME LOGIC ---
    const wordEntry = COMMON_WORDS_EN.find(w => w.word === gameState.currentGuess);
    const translation = wordEntry ? wordEntry.translation : null;
    const newHistoryItem = { word: gameState.currentGuess, translation };
    const newHistory = [...gameState.history, newHistoryItem];

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      const currentStatus = newKeyStatuses[char];
      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      updateStats(true, gameState.secretWord);
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      updateStats(false, gameState.secretWord);
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      history: newHistory,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null,
      error: null
    }));
  };

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (view !== 'game') return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;

    if (e.key === 'Enter') {
      handleEnter();
    } else if (e.key === 'Backspace') {
      handleDelete();
    } else {
      const char = e.key.toUpperCase();
      const isEnChar = /^[A-Z]$/.test(char);
      const isRuChar = /^[А-ЯЁ]$/.test(char);

      if (settings.language === 'EN' && isEnChar) handleChar(char);
      else if (settings.language === 'RU' && isRuChar) handleChar(char);
    }
  }, [gameState, settings, view, keyStatuses, userProfile]); 

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);


  // --- Feature Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploadingDict(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const text = event.target?.result as string;
      const rawWords = text.split(/[\n\s,]+/);
      const cleanedWords = rawWords
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
        .filter(w => w.length > 0);

      setUserProfile(prev => ({
        ...prev,
        customDictionaryEn: cleanedWords
      }));

      try {
        await userService.updateUserDictionary(settings.username, cleanedWords);
      } catch (e) {
        console.error("Failed to upload dictionary", e);
      } finally {
        setIsUploadingDict(false);
      }
    };
    reader.readAsText(file);
  };

  const fetchHint = async () => {
    if (gameState.gameStatus !== 'playing') return;

    // Calculate which dictionary to use for the hint pool
    let hintPool: string[] = [];

    if (settings.language === 'EN') {
      if (settings.dictionarySource === 'custom' && userProfile.customDictionaryEn.length > 0) {
        hintPool = userProfile.customDictionaryEn;
      } else if (settings.dictionarySource === 'anya') {
        hintPool = ANYAS_DICTIONARY;
      } else {
        // Built-in Dictionary: Use ALL words for hints to allow powerful elimination
        hintPool = COMMON_WORDS_EN.map(w => w.word);
      }
    } else {
      // Russian dictionary
      hintPool = COMMON_WORDS_RU.map(w => w.word); // Assuming EnrichedWord structure
    }

    // Filter potential hints by current word length
    hintPool = hintPool.filter(w => w.length === settings.wordLength);

    setGameState(prev => ({ ...prev, loadingHint: true }));

    // Simulate a brief "thinking" delay for UX consistency
    setTimeout(() => {
      const bestWord = getBestEliminationHint(
        gameState.secretWord, 
        gameState.guesses, 
        hintPool
      );

      const hintText = bestWord 
        ? `Попробуйте слово: ${bestWord}` 
        : "Нет подходящих слов для подсказки.";

      setGameState(prev => ({ 
        ...prev, 
        hint: hintText, 
        loadingHint: false 
      }));
    }, 500);
  };

