           <div className="w-full mb-1 shrink-0 flex flex-col items-center justify-end gap-1">

             {/* History Ticker - COMPACT FOR MOBILE */}
             {gameState.history.length > 0 && (
               <div 
                 ref={historyScrollRef}
                 className="w-full overflow-x-auto whitespace-nowrap no-scrollbar py-1 px-2 flex gap-2"
               >
                 {gameState.history.map((item, idx) => (
                   <div key={idx} className="inline-flex items-center bg-white border border-indigo-100 rounded-lg shadow-sm px-2 py-1 animate-bounce-in">
                     <span className="font-bold text-gray-800 text-xs">{item.word}</span>
                     {item.translation && (
                       <>
                         <span className="mx-1 text-gray-300 text-xs">|</span>
                         <span className="text-indigo-600 text-xs max-w-[80px] truncate">{item.translation}</span>
                       </>
                     )}
                   </div>
                 ))}
               </div>
             )}

             {/* Hint Button - COMPACT */}
             {!gameState.hint && !gameState.loadingHint ? (
               <button 
                onClick={fetchHint}
                className="text-xs bg-indigo-50 border border-indigo-100 text-indigo-700 px-3 py-1.5 rounded-full font-semibold hover:bg-indigo-100 transition shadow-sm"
               >
                 💡 Подсказка
               </button>
             ) : gameState.loadingHint ? (
               <div className="bg-indigo-50 border border-indigo-100 text-indigo-500 px-3 py-1.5 rounded-full text-xs font-semibold flex items-center gap-2">
                 <LoaderIcon /> Думаю...
               </div>
             ) : (
               <div className="bg-indigo-50 border border-indigo-200 text-indigo-800 p-2 rounded-lg text-xs text-center shadow-sm animate-fade-in w-full max-h-16 overflow-y-auto">
                 <span className="font-bold">Подсказка:</span> {gameState.hint}
               </div>
             )}
           </div>
        )}

        {/* Grid Container */}
        <div className="flex-grow flex items-center justify-center w-full max-h-[65vh]">
          <Grid 
            guesses={gameState.guesses}
            currentGuess={gameState.currentGuess}
            secretWord={gameState.secretWord}
            wordLength={settings.wordLength}
            maxGuesses={MAX_GUESSES}
            shakeRowIndex={shakeRowIndex}
          />
        </div>

        {gameState.gameStatus !== 'playing' && (
          <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-40 p-4 bg-white/95 backdrop-blur rounded-lg shadow-2xl border text-center animate-bounce-in w-11/12 max-w-sm">
             <h2 className="text-xl font-bold mb-2">
               {gameState.gameStatus === 'won' ? '🎉 Победа!' : '😔 Вы проиграли'}
             </h2>
             <p className="mb-2 text-gray-700">
               Загаданное слово: <span className="font-bold text-black text-lg">{gameState.secretWord}</span>
             </p>
             {/* Show Translation and Level if available */}
             {gameState.secretWordData && (
                <div className="mb-4 text-sm">
                  <span className="block text-gray-500">Перевод: <span className="text-indigo-600 font-semibold">{gameState.secretWordData.translation}</span></span>
                  <span className="block text-gray-500 text-xs mt-1">Уровень: <span className="bg-gray-200 px-1.5 py-0.5 rounded text-gray-700 font-bold">{gameState.secretWordData.level}</span></span>
                </div>
             )}
             <div className="flex flex-col gap-2">
                 <button 
                   onClick={() => setView('review')}
                   className="w-full bg-indigo-50 text-indigo-700 border border-indigo-100 px-4 py-3 rounded-lg font-bold hover:bg-indigo-100 transition flex items-center justify-center gap-2"
                 >
                   <ListIcon /> Посмотреть слова
                 </button>
                 <div className="flex gap-2 justify-center">
                    <button 
                      onClick={() => setView('landing')}
                      className="flex-1 bg-gray-100 text-gray-700 px-4 py-3 rounded-lg font-bold hover:bg-gray-200 transition"
                    >
                      Меню
                    </button>
                    <button 
                      onClick={startNewGame}
                      className="flex-1 bg-green-600 text-white px-4 py-3 rounded-lg font-bold hover:bg-green-700 flex items-center justify-center gap-2 transition shadow-md"
                    >
                      <RefreshIcon /> Играть снова
                    </button>
                 </div>
             </div>
          </div>
        )}
      </main>

      <footer className="w-full bg-gray-100 pb-4 pt-2 border-t flex justify-center shrink-0">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>
    </div>
  );

  // --- Main Switch ---
  let content;
  if (view === 'landing') content = renderLanding();
  else if (view === 'profile') content = renderProfile();
  else if (view === 'setup') content = renderSetup();
  else if (view === 'review') content = renderReview();
  else content = renderGame();

  return (
    <>
      {renderAuthModal()}
      {renderRulesModal()}

      {/* Pet is visible in landing and setup views. 
          Hidden in game view to avoid overlapping keyboard/grid on mobile. */}
      {userProfile.username !== 'Guest' && (view === 'landing' || view === 'setup') && (
        <PetWidget pet={userProfile.pet} onClick={() => setShowJailModal(true)} />
      )}

      {/* Jail Modal */}
      <WordJailModal 
        isOpen={showJailModal} 
        onClose={() => setShowJailModal(false)}
        jail={userProfile.wordJail}
        onFreeAttempt={handleJailAttempt}
        pet={userProfile.pet}
      />

      {content}
    </>
  );
};

export default App;

const handleEnter = async () => {
  if (gameState.gameStatus !== 'playing') return;

  if (gameState.currentGuess.length !== settings.wordLength) {
     setGameState(prev => ({ ...prev, error: "Недостаточно букв" }));
     triggerShake();
     return;
  }

  const validWords = getValidationPool();
  if (!validWords.includes(gameState.currentGuess)) {
    // --- NEW: MISTAKE TRAPPING ---
    // User entered an invalid word. Check for typos.

    // Determine which pool to search for typos based on the active dictionary
    let typoSearchPool = validWords; // Default to all valid words

    if (settings.language === 'EN') {
       if (settings.dictionarySource === 'custom') {
          typoSearchPool = userProfile.customDictionaryEn;
       } else if (settings.dictionarySource === 'anya') {
          typoSearchPool = ANYAS_DICTIONARY;
       }
    }

    // Only look for words of the correct length to ensure valid suggestions for the game format
    const relevantPool = typoSearchPool.filter(w => w.length === settings.wordLength);

    const typoCorrection = findClosestWord(gameState.currentGuess, relevantPool, 1);

    if (typoCorrection && userProfile.username !== 'Guest') {
       // Found a likely intended word. Send it to Jail!
       // Get translation if available (Try Common dictionary first as it has metadata)
       const wordEntry = COMMON_WORDS_EN.find(w => w.word === typoCorrection);
       const translation = wordEntry ? wordEntry.translation : '';

       // Update UI toast
       setGameState(prev => ({ ...prev, error: `Вы имели в виду ${typoCorrection}? Сохранено в Тюрьму!` }));

       // Async update
       try {
         const jailed = await userService.addWordToJail(userProfile.username, typoCorrection, translation);
         setUserProfile(prev => {
           // Replace if exists or push
           const existingIdx = prev.wordJail.findIndex(w => w.word === typoCorrection);
           const newJail = [...prev.wordJail];
           if (existingIdx >= 0) newJail[existingIdx] = jailed;
           else newJail.push(jailed);

           return { ...prev, wordJail: newJail, pet: { ...prev.pet, mood: 'sad' } }; // Pet gets sad on mistakes
         });
       } catch (e) { console.error(e); }

    } else {
       setGameState(prev => ({ ...prev, error: "Такого слова нет в словаре" }));
    }

    triggerShake();
    return;
  }

  // --- EXISTING GAME LOGIC ---
  const wordEntry = COMMON_WORDS_EN.find(w => w.word === gameState.currentGuess);
  const translation = wordEntry ? wordEntry.translation : null;
  const newHistoryItem = { word: gameState.currentGuess, translation };
  const newHistory = [...gameState.history, newHistoryItem];

  const newGuesses = [...gameState.guesses, gameState.currentGuess];

  const newKeyStatuses = { ...keyStatuses };
  const secretArr = gameState.secretWord.split('');
  const guessArr = gameState.currentGuess.split('');

  guessArr.forEach((char, i) => {
    const currentStatus = newKeyStatuses[char];
    if (char === secretArr[i]) {
      newKeyStatuses[char] = 'correct';
    } else if (gameState.secretWord.includes(char)) {
      if (currentStatus !== 'correct') {
        newKeyStatuses[char] = 'present';
      }
    } else {
      if (currentStatus !== 'correct' && currentStatus !== 'present') {
        newKeyStatuses[char] = 'absent';
      }
    }
  });
  setKeyStatuses(newKeyStatuses);

  let newStatus: GameState['gameStatus'] = 'playing';
  if (gameState.currentGuess === gameState.secretWord) {
    newStatus = 'won';
    updateStats(true, gameState.secretWord);
  } else if (newGuesses.length >= MAX_GUESSES) {
    newStatus = 'lost';
    updateStats(false, gameState.secretWord);
  }

  setGameState(prev => ({
    ...prev,
    guesses: newGuesses,
    history: newHistory,
    currentGuess: '',
    gameStatus: newStatus,
    rowIndex: prev.rowIndex + 1,
    hint: null,
    error: null
  }));
};

import React, { useState, useEffect } from 'react';
import { Grid } from './components/Grid';
import { Keyboard } from './components/Keyboard';
import { PetWidget } from './components/PetWidget';
import { WordJailModal } from './components/WordJailModal';
import { 
  GameState, 
  GameSettings, 
  UserProfile, 
  CharStatus
} from './types';
import { MAX_GUESSES } from './constants';
import { COMMON_WORDS_EN, ALL_WORDS_EN } from './dictionaries/english';
import { ALL_WORDS_RU } from './dictionaries/russian';
import { ANYAS_DICTIONARY } from './dictionaries/anya';
import { userService } from './services/userService';
import { findClosestWord } from './utils/textUtils';

const DEFAULT_SETTINGS: GameSettings = {
  language: 'EN',
  wordLength: 5,
  useCustomDictionary: false,
  dictionarySource: 'builtin',
  difficulty: 'A1',
  username: 'Guest'
};

const DEFAULT_GAME_STATE: GameState = {
  secretWord: '',
  guesses: [],
  history: [],
  currentGuess: '',
  gameStatus: 'playing',
  rowIndex: 0,
  hint: null,
  loadingHint: false,
  error: null
};

// Placeholder for user profile if not logged in
const GUEST_PROFILE: UserProfile = {
  username: 'Guest',
  customDictionaryEn: [],
  stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} },
  wordJail: [],
  pet: { name: 'Owl', level: 1, mood: 'neutral', xp: 0 }
};

export default function App() {
  const [settings, setSettings] = useState<GameSettings>(DEFAULT_SETTINGS);
  const [userProfile, setUserProfile] = useState<UserProfile>(GUEST_PROFILE);
  const [gameState, setGameState] = useState<GameState>(DEFAULT_GAME_STATE);
  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});
  const [shakeRowIndex, setShakeRowIndex] = useState<number | null>(null);
  const [isJailOpen, setIsJailOpen] = useState(false);

  const getValidationPool = (): string[] => {
    if (settings.language === 'RU') return ALL_WORDS_RU;
    if (settings.dictionarySource === 'anya') return ANYAS_DICTIONARY;
    if (settings.dictionarySource === 'custom') return userProfile.customDictionaryEn;
    return ALL_WORDS_EN;
  };

  const getRandomWord = (): string => {
    const pool = getValidationPool().filter(w => w.length === settings.wordLength);
    // Fallback if pool is empty or no words of length match
    if (pool.length === 0) return "ERROR";
    return pool[Math.floor(Math.random() * pool.length)];
  };

  const startNewGame = () => {
    const word = getRandomWord();
    setGameState({
      ...DEFAULT_GAME_STATE,
      secretWord: word,
    });
    setKeyStatuses({});
  };

  // Initialize game on load
  useEffect(() => {
    startNewGame();
  }, []); 

  const triggerShake = () => {
    setShakeRowIndex(gameState.rowIndex);
    setTimeout(() => setShakeRowIndex(null), 500);
  };

  const updateStats = (won: boolean, word: string) => {
    if (userProfile.username === 'Guest') return;

    const newStats = { ...userProfile.stats };
    newStats.gamesPlayed += 1;
    if (won) {
      newStats.gamesWon += 1;
      newStats.wordsGuessed[word] = (newStats.wordsGuessed[word] || 0) + 1;
    }

    // Optimistic update
    setUserProfile(prev => ({ ...prev, stats: newStats }));

    // Sync with backend
    userService.updateUserStats(userProfile.username, newStats).catch(console.error);
  };

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({
        ...prev,
        currentGuess: prev.currentGuess + char
      }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({
      ...prev,
      currentGuess: prev.currentGuess.slice(0, -1)
    }));
  };

  const handleEnter = async () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) {
       setGameState(prev => ({ ...prev, error: "Недостаточно букв" }));
       triggerShake();
       return;
    }

    const validWords = getValidationPool();
    if (!validWords.includes(gameState.currentGuess)) {
      // --- NEW: MISTAKE TRAPPING ---
      // User entered an invalid word. Check for typos.

      // Determine which pool to search for typos based on the active dictionary
      let typoSearchPool = validWords; // Default to all valid words

      if (settings.language === 'EN') {
         if (settings.dictionarySource === 'custom') {
            typoSearchPool = userProfile.customDictionaryEn;
         } else if (settings.dictionarySource === 'anya') {
            typoSearchPool = ANYAS_DICTIONARY;
         }
      }

      // Only look for words of the correct length to ensure valid suggestions for the game format
      const relevantPool = typoSearchPool.filter(w => w.length === settings.wordLength);

      const typoCorrection = findClosestWord(gameState.currentGuess, relevantPool, 1);

      if (typoCorrection && userProfile.username !== 'Guest') {
         // Found a likely intended word. Send it to Jail!
         // Get translation if available (Try Common dictionary first as it has metadata)
         const wordEntry = COMMON_WORDS_EN.find(w => w.word === typoCorrection);
         const translation = wordEntry ? wordEntry.translation : '';

         // Update UI toast
         setGameState(prev => ({ ...prev, error: `Вы имели в виду ${typoCorrection}? Сохранено в Тюрьму!` }));

         // Async update
         try {
           const jailed = await userService.addWordToJail(userProfile.username, typoCorrection, translation);
           setUserProfile(prev => {
             // Replace if exists or push
             const existingIdx = prev.wordJail.findIndex(w => w.word === typoCorrection);
             const newJail = [...prev.wordJail];
             if (existingIdx >= 0) newJail[existingIdx] = jailed;
             else newJail.push(jailed);

             return { ...prev, wordJail: newJail, pet: { ...prev.pet, mood: 'sad' } }; // Pet gets sad on mistakes
           });
         } catch (e) { console.error(e); }

      } else {
         setGameState(prev => ({ ...prev, error: "Такого слова нет в словаре" }));
      }

      triggerShake();
      return;
    }

    // --- EXISTING GAME LOGIC ---
    const wordEntry = COMMON_WORDS_EN.find(w => w.word === gameState.currentGuess);
    const translation = wordEntry ? wordEntry.translation : null;
    const newHistoryItem = { word: gameState.currentGuess, translation };
    const newHistory = [...gameState.history, newHistoryItem];

    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      const currentStatus = newKeyStatuses[char];
      if (char === secretArr[i]) {
        newKeyStatuses[char] = 'correct';
      } else if (gameState.secretWord.includes(char)) {
        if (currentStatus !== 'correct') {
          newKeyStatuses[char] = 'present';
        }
      } else {
        if (currentStatus !== 'correct' && currentStatus !== 'present') {
          newKeyStatuses[char] = 'absent';
        }
      }
    });
    setKeyStatuses(newKeyStatuses);

    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      updateStats(true, gameState.secretWord);
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      updateStats(false, gameState.secretWord);
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      history: newHistory,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null,
      error: null
    }));
  };

  const handleFreeAttempt = async (word: string): Promise<boolean> => {
    try {
      const result = await userService.progressWordInJail(userProfile.username, word);
      setUserProfile(prev => {
        const jail = [...prev.wordJail];
        const idx = jail.findIndex(w => w.word === result.word.word);
        if (idx !== -1) jail[idx] = result.word;
        return { ...prev, wordJail: jail, pet: result.pet };
      });
      return true;
    } catch (e) {
      console.error(e);
      return false;
    }
  };

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.ctrlKey || e.metaKey || e.altKey) return;

      const key = e.key.toUpperCase();
      if (key === 'ENTER') {
        handleEnter();
      } else if (key === 'BACKSPACE') {
        handleDelete();
      } else if (/^[A-ZА-Я]$/.test(key)) {
        handleChar(key);
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [gameState, settings, keyStatuses]); // Added keyStatuses to dependency array to ensure logic uses latest state if needed

  return (
    <div className="flex flex-col items-center min-h-screen bg-gray-50 text-gray-800 font-sans">
      <header className="w-full p-4 bg-white shadow-sm flex justify-center relative">
        <h1 className="text-2xl font-bold tracking-wider">ANNWORD</h1>
      </header>

      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-lg p-2">
        <div className="h-8 text-center mb-2">
          {gameState.error && (
            <div className="bg-black text-white px-3 py-1 rounded text-sm animate-pulse">
              {gameState.error}
            </div>
          )}
          {gameState.gameStatus === 'won' && (
            <div className="text-green-600 font-bold text-xl animate-bounce">
              Победа!
            </div>
          )}
          {gameState.gameStatus === 'lost' && (
            <div className="text-red-600 font-bold text-xl">
              {gameState.secretWord}
            </div>
          )}
        </div>

        <Grid 
          guesses={gameState.guesses}
          currentGuess={gameState.currentGuess}
          secretWord={gameState.secretWord}
          wordLength={settings.wordLength}
          maxGuesses={MAX_GUESSES}
          shakeRowIndex={shakeRowIndex}
        />
      </main>

      <div className="w-full max-w-3xl flex flex-col items-center">
        <Keyboard 
          onChar={handleChar}
          onDelete={handleDelete}
          onEnter={handleEnter}
          language={settings.language}
          letterStatuses={keyStatuses}
        />
      </div>

      {userProfile.username !== 'Guest' && (
        <>
          <PetWidget pet={userProfile.pet} onClick={() => setIsJailOpen(true)} />
          <WordJailModal 
            isOpen={isJailOpen} 
            onClose={() => setIsJailOpen(false)}
            jail={userProfile.wordJail}
            onFreeAttempt={handleFreeAttempt}
            pet={userProfile.pet}
          />
        </>
      )}

      {gameState.gameStatus !== 'playing' && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-40">
          <div className="bg-white p-8 rounded-2xl shadow-2xl flex flex-col items-center gap-4">
            <h2 className="text-2xl font-bold">
              {gameState.gameStatus === 'won' ? 'Великолепно!' : 'Не расстраивайся!'}
            </h2>
            <p>Загаданное слово: <b>{gameState.secretWord}</b></p>
            <button 
              onClick={startNewGame}
              className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition"
            >
              Новая игра
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

