);
const LockIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg>
);

const DEFAULT_SETTINGS: GameSettings = {
  language: 'EN',
  wordLength: 5,
  useCustomDictionary: false,
  dictionarySource: 'builtin',
  difficulty: 'ALL',
  username: 'Guest'
};

export default function App() {
  // Navigation State
  const [view, setView] = useState<ViewState>('landing');

  // Data State
  const [settings, setSettings] = useState<GameSettings>(DEFAULT_SETTINGS);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    username: 'Guest',
    customDictionaryEn: [],
    stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} },
    wordJail: [],
    pet: { name: 'Owl', level: 1, mood: 'neutral', xp: 0 }
  });

  // UI State
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isJailOpen, setIsJailOpen] = useState(false);
  const [isUploadingDict, setIsUploadingDict] = useState(false);
  const [setupError, setSetupError] = useState<string | null>(null);
  const [shakeRowIndex, setShakeRowIndex] = useState<number | null>(null);

  // Auth State
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authUsername, setAuthUsername] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authError, setAuthError] = useState<string | null>(null);

  // Game State
  const [gameState, setGameState] = useState<GameState>({
    secretWord: '',
    secretWordData: null,
    guesses: [],
    history: [],
    currentGuess: '',
    gameStatus: 'playing',
    rowIndex: 0,
    hint: null,
    loadingHint: false,
    error: null,
  });
  const [keyStatuses, setKeyStatuses] = useState<Record<string, CharStatus>>({});

  // Refs
  const historyScrollRef = useRef<HTMLDivElement>(null);

  // Scroll history to right when it updates
  useEffect(() => {
    if (historyScrollRef.current) {
      historyScrollRef.current.scrollLeft = historyScrollRef.current.scrollWidth;
    }
  }, [gameState.history]);

  // --- HELPERS ---

  const getValidationPool = useCallback((): string[] => {
    if (settings.language === 'RU') return ALL_WORDS_RU;

    // English Logic
    let base = ALL_WORDS_EN;

    if (settings.dictionarySource === 'anya') {
       // Combine base with Anya to ensure we validate against standard words too? 
       // Or strictly Anya? Wordle usually validates against a large dictionary.
       // User request implies validation against custom dict for typos, but normally valid words are broad.
       // Let's keep validation broad (ALL_WORDS) + Specific Dict Words
       return Array.from(new Set([...base, ...ANYAS_DICTIONARY]));
    }

    if (settings.dictionarySource === 'custom') {
       return Array.from(new Set([...base, ...userProfile.customDictionaryEn]));
    }

    return base;
  }, [settings, userProfile]);

  const getSecretWordPool = useCallback((): EnrichedWord[] => {
     if (settings.language === 'RU') return COMMON_WORDS_RU;

     if (settings.dictionarySource === 'anya') {
       return ANYAS_DICTIONARY.map(w => ({ word: w, translation: '', level: 'Anya' }));
     }

     if (settings.dictionarySource === 'custom') {
       return userProfile.customDictionaryEn.map(w => ({ word: w, translation: '', level: 'Custom' }));
     }

     // Builtin
     let pool = COMMON_WORDS_EN;
     if (settings.difficulty !== 'ALL') {
       pool = pool.filter(w => w.level === settings.difficulty);
     }
     return pool;
  }, [settings, userProfile]);

  // --- ACTIONS ---

  const handleAuth = async () => {
     if (!authUsername.trim() || !authPassword.trim()) return;
     setAuthError(null);
     try {
       const method = authMode === 'login' ? userService.login : userService.register;
       const profile = await method(authUsername, authPassword);
       setUserProfile(profile);
       setSettings(prev => ({ ...prev, username: profile.username }));
       setShowLoginModal(false);
       setAuthUsername('');
       setAuthPassword('');
     } catch (e: any) {
       setAuthError(e.message);
     }
  };

  const handleLogout = () => {
    setSettings({ ...DEFAULT_SETTINGS });
    setUserProfile({
      username: 'Guest',
      customDictionaryEn: [],
      stats: { gamesPlayed: 0, gamesWon: 0, wordsGuessed: {} },
      wordJail: [],
      pet: { name: 'Owl', level: 1, mood: 'neutral', xp: 0 }
    });
    setView('landing');
  };

  const startNewGame = () => {
    const pool = getSecretWordPool().filter(w => w.word.length === settings.wordLength);

    if (pool.length === 0) {
      setSetupError("Нет слов с выбранными параметрами (длина/сложность).");
      return;
    }

    const secretItem = pool[Math.floor(Math.random() * pool.length)];

    setGameState({
      secretWord: secretItem.word,
      secretWordData: secretItem,
      guesses: [],
      history: [],
      currentGuess: '',
      gameStatus: 'playing',
      rowIndex: 0,
      hint: null,
      loadingHint: false,
      error: null
    });
    setKeyStatuses({});
    setView('game');
  };

  const handleChar = (char: string) => {
    if (gameState.gameStatus !== 'playing') return;
    if (gameState.currentGuess.length < settings.wordLength) {
      setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess + char, error: null }));
    }
  };

  const handleDelete = () => {
    if (gameState.gameStatus !== 'playing') return;
    setGameState(prev => ({ ...prev, currentGuess: prev.currentGuess.slice(0, -1), error: null }));
  };

  const triggerShake = () => {
    setShakeRowIndex(gameState.rowIndex);
    setTimeout(() => setShakeRowIndex(null), 500);
  };

  const handleEnter = async () => {
    if (gameState.gameStatus !== 'playing') return;

    if (gameState.currentGuess.length !== settings.wordLength) {
       setGameState(prev => ({ ...prev, error: "Недостаточно букв" }));
       triggerShake();
       return;
    }

    const validWords = getValidationPool();
    if (!validWords.includes(gameState.currentGuess)) {
      // --- TYPO TRAPPING LOGIC ---
      // Determine the specific pool to search for typos based on the user's active dictionary choice.
      let typoSearchPool = validWords; // Default fallback

      if (settings.language === 'EN') {
         if (settings.dictionarySource === 'custom') {
            typoSearchPool = userProfile.customDictionaryEn;
         } else if (settings.dictionarySource === 'anya') {
            typoSearchPool = ANYAS_DICTIONARY;
         }
      }

      // Only consider words of the correct length from that pool
      const relevantPool = typoSearchPool.filter(w => w.length === settings.wordLength);

      // Find closest match
      const typoCorrection = findClosestWord(gameState.currentGuess, relevantPool, 1);

      if (typoCorrection && userProfile.username !== 'Guest') {
         // It's a typo of a word in their learning list! Jail it.
         const wordEntry = COMMON_WORDS_EN.find(w => w.word === typoCorrection);
         const translation = wordEntry ? wordEntry.translation : '';

         setGameState(prev => ({ ...prev, error: `Опечатка! ${typoCorrection} отправлено в тюрьму.` }));

         try {
           const jailed = await userService.addWordToJail(userProfile.username, typoCorrection, translation);
           setUserProfile(prev => {
             // Update jail in state
             const newJail = [...prev.wordJail];
             const idx = newJail.findIndex(j => j.word === typoCorrection);
             if (idx >= 0) newJail[idx] = jailed;
             else newJail.push(jailed);

             return { ...prev, wordJail: newJail, pet: { ...prev.pet, mood: 'sad' } };
           });
         } catch (e) { console.error(e); }
      } else {
         setGameState(prev => ({ ...prev, error: "Такого слова нет" }));
      }

      triggerShake();
      return;
    }

    // --- PROCESS VALID GUESS ---
    const wordEntry = COMMON_WORDS_EN.find(w => w.word === gameState.currentGuess);
    const translation = wordEntry ? wordEntry.translation : null;
    const newHistory = [...gameState.history, { word: gameState.currentGuess, translation }];
    const newGuesses = [...gameState.guesses, gameState.currentGuess];

    // Update keys
    const newKeyStatuses = { ...keyStatuses };
    const secretArr = gameState.secretWord.split('');
    const guessArr = gameState.currentGuess.split('');

    guessArr.forEach((char, i) => {
      if (char === secretArr[i]) newKeyStatuses[char] = 'correct';
      else if (gameState.secretWord.includes(char) && newKeyStatuses[char] !== 'correct') newKeyStatuses[char] = 'present';
      else if (!gameState.secretWord.includes(char) && newKeyStatuses[char] !== 'correct' && newKeyStatuses[char] !== 'present') newKeyStatuses[char] = 'absent';
    });

    let newStatus: GameState['gameStatus'] = 'playing';
    if (gameState.currentGuess === gameState.secretWord) {
      newStatus = 'won';
      // Update stats
      if (userProfile.username !== 'Guest') {
        const newStats = { ...userProfile.stats, gamesPlayed: userProfile.stats.gamesPlayed + 1, gamesWon: userProfile.stats.gamesWon + 1 };
        newStats.wordsGuessed[gameState.secretWord] = (newStats.wordsGuessed[gameState.secretWord] || 0) + 1;
        setUserProfile(prev => ({ ...prev, stats: newStats }));
        userService.updateUserStats(userProfile.username, newStats);
      }
    } else if (newGuesses.length >= MAX_GUESSES) {
      newStatus = 'lost';
      if (userProfile.username !== 'Guest') {
         const newStats = { ...userProfile.stats, gamesPlayed: userProfile.stats.gamesPlayed + 1 };
         setUserProfile(prev => ({ ...prev, stats: newStats }));
         userService.updateUserStats(userProfile.username, newStats);
      }
    }

    setGameState(prev => ({
      ...prev,
      guesses: newGuesses,
      history: newHistory,
      currentGuess: '',
      gameStatus: newStatus,
      rowIndex: prev.rowIndex + 1,
      hint: null,
      error: null
    }));
    setKeyStatuses(newKeyStatuses);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploadingDict(true);
    const reader = new FileReader();
    reader.onload = (ev) => {
      const text = ev.target?.result as string;
      const words = text.split(/[\n\s,]+/)
        .map(w => w.trim().toUpperCase().replace(/[^A-Z]/g, ''))
        .filter(w => w.length > 0);

      setUserProfile(prev => ({ ...prev, customDictionaryEn: words }));
      userService.updateUserDictionary(userProfile.username, words).finally(() => setIsUploadingDict(false));
    };
    reader.readAsText(file);
  };

  const handleJailAttempt = async (word: string) => {
    try {
      const res = await userService.progressWordInJail(userProfile.username, word);
      setUserProfile(prev => {
        const jail = prev.wordJail.map(w => w.word === word ? res.word : w);
        return { ...prev, wordJail: jail, pet: res.pet };
      });
      return true;
    } catch { return false; }
  };

  // --- KEY LISTENER ---
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (view !== 'game') return;
      if (e.ctrlKey || e.metaKey || e.altKey) return;
      const k = e.key.toUpperCase();
      if (k === 'ENTER') handleEnter();
      else if (k === 'BACKSPACE') handleDelete();
      else if (/^[A-ZА-Я]$/.test(k)) {
         if (settings.language === 'EN' && /^[A-Z]$/.test(k)) handleChar(k);
         if (settings.language === 'RU' && /^[А-Я]$/.test(k)) handleChar(k);
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [gameState, view, settings]);

  // --- RENDERERS ---

  const renderLanding = () => (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 bg-gradient-to-b from-indigo-50 to-white w-full">
      <div className="absolute top-4 right-4">
        {userProfile.username === 'Guest' ? (
          <button onClick={() => { setAuthMode('login'); setShowLoginModal(true); }} className="px-4 py-2 bg-white rounded-full shadow text-indigo-600 font-bold hover:bg-indigo-50 transition">
             Войти
          </button>
        ) : (
          <button onClick={() => setView('profile')} className="px-4 py-2 bg-white rounded-full shadow text-indigo-600 font-bold flex items-center gap-2 hover:bg-indigo-50 transition">
             <UserIcon /> {userProfile.username}
          </button>
        )}
      </div>

      <div className="text-center mb-10">
        <h1 className="text-5xl md:text-7xl font-black text-indigo-900 mb-2 tracking-tighter">
          ANN<span className="text-green-500">WORD</span>
        </h1>
        <p className="text-gray-500">Тренируй мозг, учи слова</p>
      </div>

      <div className="grid gap-4 w-full max-w-md">
        <button onClick={() => { setSettings(s => ({ ...s, language: 'EN' })); setView('setup'); }} className="p-6 bg-white rounded-2xl shadow-lg border-2 border-transparent hover:border-indigo-200 transition group text-left">
           <div className="text-2xl mb-1">🇬🇧 English</div>
           <div className="text-gray-400 text-sm group-hover:text-indigo-500">Уровни A1-C2, словарь Ани</div>
        </button>
        <button disabled className="p-6 bg-gray-50 rounded-2xl border-2 border-transparent opacity-60 text-left cursor-not-allowed">
           <div className="text-2xl mb-1">🇷🇺 Русский</div>
           <div className="text-gray-400 text-sm">В разработке</div>
        </button>
      </div>
    </div>
  );

  const renderSetup = () => (
    <div className="flex flex-col items-center min-h-screen p-4 bg-gray-50 w-full">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden mt-10">
        <div className="bg-indigo-600 p-4 text-white flex items-center">
          <button onClick={() => setView('landing')} className="p-2 hover:bg-white/20 rounded-full"><BackIcon /></button>
          <h2 className="ml-4 font-bold text-lg">Настройки игры</h2>
        </div>

        <div className="p-6 space-y-6">
          {setupError && <div className="p-3 bg-red-100 text-red-700 rounded-lg text-sm">{setupError}</div>}

          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Источник слов</label>
            <div className="space-y-2">
              <button onClick={() => setSettings(s => ({...s, dictionarySource: 'builtin'}))} className={`w-full p-3 rounded-lg border-2 text-left font-bold transition ${settings.dictionarySource === 'builtin' ? 'border-indigo-500 bg-indigo-50 text-indigo-700' : 'border-gray-100 text-gray-500'}`}>
                Школьный (Built-in)
              </button>
              <button onClick={() => setSettings(s => ({...s, dictionarySource: 'anya'}))} className={`w-full p-3 rounded-lg border-2 text-left font-bold transition ${settings.dictionarySource === 'anya' ? 'border-indigo-500 bg-indigo-50 text-indigo-700' : 'border-gray-100 text-gray-500'}`}>
                Словарь Ани
              </button>
              <button 
                onClick={() => {
                   if (userProfile.username === 'Guest') { setSetupError("Войдите, чтобы использовать свой словарь"); return; }
                   setSettings(s => ({...s, dictionarySource: 'custom'}));
                }} 
                className={`w-full p-3 rounded-lg border-2 text-left font-bold transition flex justify-between ${settings.dictionarySource === 'custom' ? 'border-indigo-500 bg-indigo-50 text-indigo-700' : 'border-gray-100 text-gray-500'}`}
              >
                <span>Мой словарь</span>
                {userProfile.username === 'Guest' && <LockIcon />}
              </button>
            </div>
          </div>

          {settings.dictionarySource === 'custom' && (
             <div className="p-4 bg-yellow-50 rounded-xl border border-yellow-100">
               <div className="text-sm font-bold text-yellow-800 mb-2">Загрузить слова (.txt)</div>
               {isUploadingDict ? <div className="text-sm text-yellow-600"><LoaderIcon /> Загрузка...</div> : <input type="file" accept=".txt" onChange={handleFileUpload} className="text-xs text-gray-500" />}
               <div className="mt-2 text-xs text-yellow-700">Слов: {userProfile.customDictionaryEn.length}</div>
             </div>
          )}

          {settings.dictionarySource === 'builtin' && (
             <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Сложность</label>
                <div className="grid grid-cols-4 gap-2">
                  {(['A1', 'A2', 'B1', 'B2', 'C1', 'C2', 'ALL'] as DifficultyLevel[]).map(lvl => (
                    <button key={lvl} onClick={() => setSettings(s => ({...s, difficulty: lvl}))} className={`py-2 rounded-lg text-sm font-bold ${settings.difficulty === lvl ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'}`}>
                      {lvl === 'ALL' ? 'Все' : lvl}
                    </button>
                  ))}
                </div>
             </div>
          )}

          <div>
             <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Длина слова</label>
             <div className="flex gap-2">
               {[4, 5, 6].map((len) => (
                 <button key={len} onClick={() => setSettings(s => ({...s, wordLength: len as WordLength}))} className={`flex-1 py-3 rounded-lg font-bold ${settings.wordLength === len ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'}`}>
                   {len}
                 </button>
               ))}
             </div>
          </div>

          <button onClick={startNewGame} className="w-full py-4 bg-green-500 text-white font-bold rounded-xl text-xl hover:bg-green-600 shadow-lg shadow-green-200 transition transform active:scale-95">
            Играть
          </button>
        </div>
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="flex flex-col items-center min-h-screen p-4 bg-gray-50 w-full">
      <div className="w-full max-w-lg bg-white rounded-3xl shadow-lg p-6 mt-10">
        <div className="flex justify-between items-center mb-6">
           <button onClick={() => setView('landing')} className="p-2 hover:bg-gray-100 rounded-full"><BackIcon /></button>
           <h2 className="text-2xl font-bold">Профиль</h2>
           {userProfile.username !== 'Guest' && (
             <button onClick={handleLogout} className="text-red-500 text-sm font-bold bg-red-50 px-3 py-1 rounded">Выйти</button>
           )}
        </div>

        <div className="flex items-center gap-4 mb-8">
           <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center text-3xl">👤</div>
           <div>
             <div className="text-xl font-bold">{userProfile.username}</div>
             <div className="text-sm text-gray-500">Уровень питомца: {userProfile.pet.level}</div>
           </div>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-6">
          <div className="bg-gray-50 p-4 rounded-xl text-center">
             <div className="text-3xl font-black text-gray-800">{userProfile.stats.gamesPlayed}</div>
             <div className="text-xs text-gray-400 uppercase">Игр</div>
          </div>
          <div className="bg-green-50 p-4 rounded-xl text-center">
             <div className="text-3xl font-black text-green-600">{userProfile.stats.gamesWon}</div>
             <div className="text-xs text-green-600 uppercase">Побед</div>
          </div>
        </div>

        <div className="mb-6">
          <h3 className="font-bold text-gray-500 mb-2 text-sm uppercase">Тюрьма слов</h3>
          <button onClick={() => setIsJailOpen(true)} className="w-full py-3 border-2 border-indigo-100 text-indigo-600 font-bold rounded-xl hover:bg-indigo-50 transition">
             Открыть тюрьму ({userProfile.wordJail.filter(w => !w.isFree).length} узников)
          </button>
        </div>
      </div>
    </div>
  );

  const renderGame = () => (
    <div className="flex flex-col h-screen items-center bg-gray-50 w-full overflow-hidden">
      <header className="w-full bg-white p-3 shadow-sm flex justify-between items-center shrink-0 z-10">
        <button onClick={() => setView('landing')} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full"><HomeIcon /></button>
        <h1 className="font-black text-xl tracking-widest">ANN<span className="text-green-500">WORD</span></h1>
        <div className="w-8"></div>
      </header>

      <main className="flex-grow flex flex-col w-full max-w-lg relative">
        {/* Toast Error */}
        <div className={`absolute top-4 left-0 right-0 flex justify-center transition-opacity duration-300 ${gameState.error ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
           <div className="bg-gray-800 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg">
             {gameState.error}
           </div>
        </div>

        {/* History / Hints Strip */}
        <div className="h-12 w-full flex items-center justify-between px-4 mt-2 shrink-0">
           <div ref={historyScrollRef} className="flex gap-2 overflow-x-auto no-scrollbar w-full mask-linear-fade">
              {gameState.history.map((h, i) => (
                <div key={i} className="flex items-center text-xs bg-white px-2 py-1 rounded border border-indigo-100 shadow-sm whitespace-nowrap">
                   <span className="font-bold mr-1">{h.word}</span>
                   {h.translation && <span className="text-indigo-400">{h.translation}</span>}
                </div>
              ))}
           </div>
        </div>

        {/* The Grid */}
        <div className="flex-grow flex items-center justify-center p-2">
           <Grid 
             guesses={gameState.guesses}
             currentGuess={gameState.currentGuess}
             secretWord={gameState.secretWord}
             wordLength={settings.wordLength}
             maxGuesses={MAX_GUESSES}
             shakeRowIndex={shakeRowIndex}
           />
        </div>
      </main>

      <footer className="w-full bg-gray-100 pb-6 pt-2 border-t shrink-0 flex justify-center">
         <Keyboard 
           onChar={handleChar}
           onDelete={handleDelete}
           onEnter={handleEnter}
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>

      {/* Game Over Modal */}
      {gameState.gameStatus !== 'playing' && (
        <div className="absolute inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl p-6 w-full max-w-sm animate-bounce-in text-center">
             <div className="text-4xl mb-4">{gameState.gameStatus === 'won' ? '🎉' : '😔'}</div>
             <h2 className="text-2xl font-black mb-2">{gameState.gameStatus === 'won' ? 'Победа!' : 'Увы...'}</h2>
             <div className="bg-gray-100 rounded-xl p-4 mb-6">
                <div className="text-xs text-gray-500 uppercase mb-1">Загаданное слово</div>
                <div className="text-2xl font-black text-indigo-700 tracking-widest">{gameState.secretWord}</div>
                {gameState.secretWordData?.translation && (
                  <div className="text-sm text-gray-600 mt-1">{gameState.secretWordData.translation}</div>
                )}
             </div>
             <div className="flex gap-3">
               <button onClick={() => setView('landing')} className="flex-1 py-3 bg-gray-200 font-bold rounded-xl text-gray-700 hover:bg-gray-300 transition">Меню</button>
               <button onClick={startNewGame} className="flex-1 py-3 bg-green-500 font-bold rounded-xl text-white hover:bg-green-600 shadow-lg shadow-green-200 transition">Еще раз</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );

  // --- MAIN RENDER ---

  let content;
  if (view === 'landing') content = renderLanding();
  else if (view === 'setup') content = renderSetup();
  else if (view === 'profile') content = renderProfile();
  else content = renderGame();

  return (
    <>
      {content}

      {/* Auth Modal */}
      {showLoginModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-6 w-full max-w-sm">
             <h3 className="text-xl font-bold mb-4">{authMode === 'login' ? 'Вход' : 'Регистрация'}</h3>
             {authError && <div className="text-red-500 text-sm mb-2">{authError}</div>}
             <input className="w-full border p-3 rounded-lg mb-3" placeholder="Имя" value={authUsername} onChange={e => setAuthUsername(e.target.value)} />
             <input className="w-full border p-3 rounded-lg mb-4" type="password" placeholder="Пароль" value={authPassword} onChange={e => setAuthPassword(e.target.value)} />
             <button onClick={handleAuth} className="w-full bg-indigo-600 text-white font-bold py-3 rounded-lg mb-2">
               {authMode === 'login' ? 'Войти' : 'Создать'}
             </button>
             <button onClick={() => setShowLoginModal(false)} className="w-full text-gray-400 text-sm">Отмена</button>
             <div className="mt-4 text-center text-sm text-indigo-500 cursor-pointer" onClick={() => setAuthMode(m => m === 'login' ? 'register' : 'login')}>
               {authMode === 'login' ? 'Нет аккаунта? Регистрация' : 'Есть аккаунт? Вход'}
             </div>
          </div>
        </div>
      )}

      {/* Pet Widget - HIDDEN ON GAME SCREEN to prevent overlap */}
      {userProfile.username !== 'Guest' && view !== 'game' && (
        <PetWidget pet={userProfile.pet} onClick={() => setIsJailOpen(true)} />
      )}

      <WordJailModal 
        isOpen={isJailOpen}
        onClose={() => setIsJailOpen(false)}
        jail={userProfile.wordJail}
        pet={userProfile.pet}
        onFreeAttempt={handleJailAttempt}
      />
    </>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameSettings, GameState, CharStatus, UserProfile, WordLength, EnrichedWord, ViewState, DictionarySource, DifficultyLevel } from './types';
