                <div className="mb-4 text-sm">
                  <span className="block text-gray-500">Перевод: <span className="text-indigo-600 font-semibold">{gameState.secretWordData.translation}</span></span>
                  <span className="block text-gray-500 text-xs mt-1">Уровень: <span className="bg-gray-200 px-1.5 py-0.5 rounded text-gray-700 font-bold">{gameState.secretWordData.level}</span></span>
                </div>
             )}
             <div className="flex flex-col gap-2">
                 <button 
                   onClick={() => setView('review')}
                   className="w-full bg-indigo-50 text-indigo-700 border border-indigo-100 px-4 py-3 rounded-lg font-bold hover:bg-indigo-100 transition flex items-center justify-center gap-2"
                 >
                   <ListIcon /> Посмотреть слова
                 </button>
                 <div className="flex gap-2 justify-center">
                    <button 
                      onClick={() => setView('landing')}
                      className="flex-1 bg-gray-100 text-gray-700 px-4 py-3 rounded-lg font-bold hover:bg-gray-200 transition"
                    >
                      Меню
                    </button>
                    <button 
                      onClick={startNewGame}
                      className="flex-1 bg-green-600 text-white px-4 py-3 rounded-lg font-bold hover:bg-green-700 flex items-center justify-center gap-2 transition shadow-md"
                    >
                      <RefreshIcon /> Играть снова
                    </button>
                 </div>
             </div>
          </div>
        )}
      </main>

      <footer className="w-full bg-gray-100 pb-4 pt-2 border-t flex justify-center shrink-0">
         <Keyboard 
           onChar={handleChar} 
           onDelete={handleDelete} 
           onEnter={handleEnter} 
           language={settings.language}
           letterStatuses={keyStatuses}
         />
      </footer>
    </div>
  );

  // --- Main Switch ---
  let content;
  if (view === 'landing') content = renderLanding();
  else if (view === 'profile') content = renderProfile();
  else if (view === 'setup') content = renderSetup();
  else if (view === 'review') content = renderReview();
  else content = renderGame();

  return (
    <>
      {renderAuthModal()}
      {renderRulesModal()}

      {/* Pet is visible in landing and setup views. 
          Hidden in game view to avoid overlapping keyboard/grid on mobile. */}
      {userProfile.username !== 'Guest' && (view === 'landing' || view === 'setup') && (
        <PetWidget pet={userProfile.pet} onClick={() => setShowJailModal(true)} />
      )}

      {/* Jail Modal */}
      <WordJailModal 
        isOpen={showJailModal} 
        onClose={() => setShowJailModal(false)}
        jail={userProfile.wordJail}
        onFreeAttempt={handleJailAttempt}
        pet={userProfile.pet}
        language={settings.language}
      />

      {content}
    </>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { JailedWord, PetState, Language, CharStatus } from '../types';
import { createGapWord, scrambleWord } from '../utils/textUtils';
import { Keyboard } from './Keyboard';

interface WordJailModalProps {
  isOpen: boolean;
  onClose: () => void;
  jail: JailedWord[];
  onFreeAttempt: (word: string) => Promise<boolean>;
  pet: PetState;
  language: Language;
}

type MiniGameType = 'gap' | 'scramble' | 'none';

// --- Icons ---
const HungryCatIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" width="40" height="40" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="50" cy="50" r="40" className="fill-orange-100 stroke-orange-400" />
    <path d="M30 40 Q50 45 70 40" className="stroke-orange-500" strokeWidth="3" />
    <circle cx="35" cy="35" r="4" className="fill-orange-800 stroke-none" />
    <circle cx="65" cy="35" r="4" className="fill-orange-800 stroke-none" />
    <path d="M45 55 L50 60 L55 55" className="stroke-orange-800" fill="none" />
    <path d="M50 60 L50 65" className="stroke-orange-800" />
    <path d="M35 70 Q50 85 65 70" className="stroke-red-500 fill-red-200" strokeWidth="2" /> {/* Hungry Mouth */}
    <path d="M15 25 L25 15 L35 25" className="stroke-orange-400 fill-orange-200" />
    <path d="M85 25 L75 15 L65 25" className="stroke-orange-400 fill-orange-200" />
  </svg>
);

const HappyCatIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" width="120" height="120" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
     <circle cx="50" cy="50" r="45" className="fill-green-100 stroke-green-500" />
     <path d="M30 45 Q50 35 70 45" className="stroke-green-600" fill="none" strokeWidth="3" /> {/* Happy Eyes */}
     <path d="M45 55 L50 60 L55 55" className="stroke-green-800" fill="none" />
     <path d="M50 60 L50 65" className="stroke-green-800" />
     <path d="M35 70 Q50 80 65 70" className="stroke-green-600 fill-none" strokeWidth="3" /> {/* Smile */}
     <path d="M10 25 L25 15 L35 25" className="stroke-green-500 fill-green-200" />
     <path d="M90 25 L75 15 L65 25" className="stroke-green-500 fill-green-200" />
  </svg>
);

export const WordJailModal: React.FC<WordJailModalProps> = ({ isOpen, onClose, jail, onFreeAttempt, pet, language }) => {
  const [activeWord, setActiveWord] = useState<JailedWord | null>(null);
  const [gameType, setGameType] = useState<MiniGameType>('none');
  const [userInput, setUserInput] = useState('');
  const [feedback, setFeedback] = useState<'none' | 'success' | 'fail'>('none');
  const [highlightedKeys, setHighlightedKeys] = useState<Record<string, CharStatus>>({});

  // Game Data
  const [scrambled, setScrambled] = useState('');
  const [gapData, setGapData] = useState<{ display: string, missingIndices: number[] } | null>(null);

  // Filter jailed words
  const prisoners = jail.filter(w => !w.isFree);
  const freed = jail.filter(w => w.isFree);

  useEffect(() => {
    if (!isOpen) {
      resetGame();
    }
  }, [isOpen]);

  // Update highlighted keys when active word changes
  useEffect(() => {
    if (activeWord) {
      const keys: Record<string, CharStatus> = {};
      const target = activeWord.word.toUpperCase();
      // Highlight letters present in the word to help the user
      target.split('').forEach(char => {
        keys[char] = 'present'; // Using 'present' (yellow) style for hints
      });
      setHighlightedKeys(keys);
    } else {
      setHighlightedKeys({});
    }
  }, [activeWord]);

  const resetGame = () => {
    setActiveWord(null);
    setGameType('none');
    setUserInput('');
    setFeedback('none');
    setHighlightedKeys({});
  };

  const startMiniGame = (wordItem: JailedWord) => {
    setActiveWord(wordItem);
    setFeedback('none');
    setUserInput('');

    // Randomly choose game type
    const type: MiniGameType = Math.random() > 0.5 ? 'gap' : 'scramble';
    setGameType(type);

    if (type === 'scramble') {
      setScrambled(scrambleWord(wordItem.word));
    } else {
      setGapData(createGapWord(wordItem.word));
    }
  };

  const checkAnswer = async () => {
    if (!activeWord) return;

    let isCorrect = false;
    const target = activeWord.word.toUpperCase();
    const attempt = userInput.toUpperCase().trim();

    // In spelling practice, strict equality is expected
    isCorrect = attempt === target;

    if (isCorrect) {
      setFeedback('success');
      // Update logic in backend
      await onFreeAttempt(activeWord.word);
      setTimeout(() => resetGame(), 1000); // Close mini-game after success
    } else {
      setFeedback('fail');
      // Use shake logic or visual error
      setTimeout(() => {
         setFeedback('none');
         setUserInput(''); // Reset input on fail to try again
      }, 800);
    }
  };

  // Keyboard Handlers
  const handleChar = (char: string) => {
    if (!activeWord) return;
    if (userInput.length < activeWord.word.length) {
      setUserInput(prev => prev + char);
    }
  };

  const handleDelete = () => {
    setUserInput(prev => prev.slice(0, -1));
  };

  const handleEnter = () => {
    checkAnswer();
  };

  if (!isOpen) return null;

  // -- Views --

  const renderSuccessState = () => (
    <div className="flex flex-col items-center justify-center h-full p-6 text-center animate-fade-in">
      <div className="animate-bounce mb-6">
        <HappyCatIcon />
      </div>
      <h2 className="text-2xl font-bold text-green-700 mb-2">Тюрьма пуста!</h2>
      <p className="text-gray-500 mb-8">Питомец сыт и счастлив. Отличная работа!</p>
      <button 
        onClick={onClose}
        className="w-full bg-green-500 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-green-600 transition transform hover:-translate-y-1"
      >
        В меню
      </button>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-0 sm:p-4 animate-fade-in">
      <div className="bg-white sm:rounded-3xl shadow-2xl w-full max-w-lg h-full sm:h-[85vh] flex flex-col relative overflow-hidden">

        {/* Header */}
        <div className="bg-orange-50 border-b border-orange-100 p-4 text-orange-900 flex justify-between items-center shrink-0 z-10">
          <div className="flex items-center gap-3">
            <HungryCatIcon />
            <div>
              <h2 className="text-xl font-bold">Тюрьма слов</h2>
              <p className="text-xs text-orange-600/70 font-semibold">Освободи слова для Питомца!</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-orange-100 rounded-full text-xl font-bold">✕</button>
        </div>

        {/* Content Area */}
        <div className="flex-grow overflow-y-auto bg-slate-50 flex flex-col">

          {prisoners.length === 0 && !activeWord ? (
             renderSuccessState()
          ) : activeWord ? (
            /* Active Mini Game */
            <div className="flex flex-col h-full">
               <div className="flex-grow flex flex-col items-center justify-center p-6 gap-6 animate-bounce-in">
                  <div className="bg-white p-6 rounded-2xl shadow-sm border-2 border-indigo-50 w-full text-center">
                    <h3 className="text-sm font-bold text-gray-400 uppercase tracking-widest mb-4">
                      {gameType === 'scramble' ? 'Собери слово' : 'Впиши слово целиком'}
                    </h3>

                    <div className="text-3xl sm:text-4xl font-black text-indigo-600 tracking-widest mb-2 break-all">
                      {gameType === 'scramble' ? scrambled : gapData?.display}
                    </div>

                    {activeWord.translation && (
                      <p className="text-sm text-gray-500 font-medium">{activeWord.translation}</p>
                    )}
                  </div>

                  {/* Input Display Area */}
                  <div className={`w-full bg-white rounded-xl h-16 flex items-center justify-center text-3xl font-bold tracking-wider border-2 shadow-inner transition-colors ${
                      feedback === 'fail' ? 'border-red-400 bg-red-50 text-red-600' : 
                      feedback === 'success' ? 'border-green-400 bg-green-50 text-green-600' : 'border-gray-200 text-gray-800'
                  }`}>
                     {userInput}
                     <span className="w-0.5 h-8 bg-indigo-400 animate-pulse ml-1"></span>
                  </div>

                  {/* Action Buttons */}
                  <div className="flex justify-between w-full mt-2 px-2">
                     <button onClick={resetGame} className="text-gray-400 text-sm font-bold hover:text-gray-600">Отмена</button>
                     <div className="text-xs text-indigo-400 font-bold uppercase tracking-wide">Вводите буквы</div>
                  </div>
               </div>

               {/* Custom Keyboard for Input */}
               <div className="bg-white border-t border-gray-100 pt-2 pb-6 shrink-0">
                  <Keyboard 
                    onChar={handleChar}
                    onDelete={handleDelete}
                    onEnter={handleEnter}
                    language={language}
                    letterStatuses={highlightedKeys} 
                  />
               </div>
            </div>
          ) : (
            /* List of Prisoners */
            <div className="p-4 space-y-6">

              {/* Prisoners Section */}
              <div>
                <h3 className="text-sm font-bold text-slate-500 uppercase mb-3 flex items-center gap-2 px-1">
                  Заключенные ({prisoners.length})
                </h3>
                <div className="grid grid-cols-1 gap-3">
                  {prisoners.map((w) => (
                    <button 
                      key={w.word}
                      onClick={() => startMiniGame(w)}
                      className="bg-white border-2 border-slate-200 p-4 rounded-xl flex items-center justify-between hover:border-indigo-400 hover:shadow-md transition group text-left active:scale-[0.98]"
                    >
                      <div>
                        <div className="font-bold text-slate-800 text-lg group-hover:text-indigo-600">{w.word}</div>
                        {w.translation && <div className="text-sm text-slate-400">{w.translation}</div>}
                      </div>

                      {/* Jail Bars Visualization */}
                      <div className="flex flex-col items-end gap-1">
                         <span className="text-[10px] font-bold text-slate-300 uppercase">Прогресс</span>
                         <div className="flex gap-1">
                            {[1, 2, 3].map(step => (
                              <div key={step} className={`w-3 h-8 rounded-full transition-all ${step <= w.correctionLevel ? 'bg-green-400 shadow-sm' : 'bg-slate-100'}`}></div>
                            ))}
                         </div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Freed Section */}
              {freed.length > 0 && (
                <div className="pt-4 border-t border-slate-200">
                  <h3 className="text-sm font-bold text-slate-400 uppercase mb-3 px-1">Освобожденные ({freed.length})</h3>
                  <div className="flex flex-wrap gap-2">
                    {freed.map(w => (
                      <span key={w.word} className="bg-green-50 text-green-700 px-3 py-1.5 rounded-lg text-xs font-bold border border-green-100">
                        {w.word}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};
